import React, { useState, useEffect, useMemo } from 'react';
import { db, isMockMode } from '../services/firebase';
import { Student, ViewState, MadrasahData, AttendanceRecord } from '../types';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { id as localeID } from 'date-fns/locale/id'; 
import { jsPDF } from "jspdf";
import autoTable from 'jspdf-autotable';
import { 
    CalendarIcon, Loader2, ChevronLeft, ChevronRight, 
    Search, ArrowLeftIcon, 
    CameraIcon, PencilIcon,
    HeartIcon, PrinterIcon
} from './Icons';

const Presensi: React.FC<{ onBack: () => void, onNavigate: (v: ViewState) => void }> = ({ onBack, onNavigate }) => {
  const [date, setDate] = useState<Date>(new Date());
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [attendanceSnapshot, setAttendanceSnapshot] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [madrasahInfo, setMadrasahInfo] = useState<MadrasahData | null>(null);

  const [isHaidMode, setIsHaidMode] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);

  useEffect(() => {
    setLoading(true);
    const loadData = async () => {
        if (isMockMode) {
            setAllStudents([
                { id: '1', namaLengkap: 'ADELIA SRI SUNDARI', tingkatRombel: 'XII IPA 1', nisn: '0086806447', status: 'Aktif', jenisKelamin: 'Perempuan', idUnik: '25002' } as any,
                { id: '2', namaLengkap: 'AHMAD DAHLAN', tingkatRombel: 'X IPA 1', nisn: '0086806448', status: 'Aktif', jenisKelamin: 'Laki-laki', idUnik: '25010' } as any,
                { id: '3', namaLengkap: 'BUDI SANTOSO', tingkatRombel: 'XI IPS 1', nisn: '0086806449', status: 'Aktif', jenisKelamin: 'Laki-laki', idUnik: '25015' } as any
            ]);
            setLoading(false); 
            return;
        }
        if (!db) return;
        const dateStr = format(date, "yyyy-MM-dd");

        const unsubS = db.collection("students").where("status", "==", "Aktif").onSnapshot(s => {
            setAllStudents(s.docs.map(d => ({ id: d.id, ...d.data() } as Student)));
        });

        const unsubA = db.collection("attendance").where("date", "==", dateStr).onSnapshot(s => {
            setAttendanceSnapshot(s.docs.map(d => ({ id: d.id, ...d.data() } as AttendanceRecord)));
            setLoading(false);
        });

        db.collection('settings').doc('madrasahInfo').get().then(doc => {
            if (doc.exists) setMadrasahInfo(doc.data() as MadrasahData);
        });

        return () => { unsubS(); unsubA(); };
    };
    loadData();
  }, [date]);

  const displayData = useMemo(() => {
    // FIX: Tambahkan fallback string kosong pada localeCompare untuk mencegah error undefined
    const students = [...allStudents].sort((a, b) => 
        (a.namaLengkap || '').localeCompare(b.namaLengkap || '')
    );
    const attMap = new Map(attendanceSnapshot.map(r => [r.studentId, r]));

    return students.map(s => {
        const record = attMap.get(s.id!);
        return (record || {
            id: `${s.id}_${format(date, "yyyy-MM-dd")}`,
            studentId: s.id!, studentName: s.namaLengkap, class: s.tingkatRombel,
            status: 'Alpha', checkIn: null, checkOut: null, duha: null, zuhur: null, ashar: null,
            jenisKelamin: s.jenisKelamin, idUnik: s.idUnik
        } as any);
    });
  }, [allStudents, attendanceSnapshot, date]);

  const handleEditClick = (record: AttendanceRecord) => {
      if (isHaidMode) {
          handleQuickHaidAction(record);
          return;
      }
      setEditingRecord(record);
      setIsModalOpen(true);
  };

  const handleQuickHaidAction = async (record: AttendanceRecord) => {
      if (record.status === 'Haid') return;
      const student = allStudents.find(s => s.id === record.studentId);
      if (student?.jenisKelamin === 'Laki-laki') {
          toast.error("Mode Haid hanya untuk siswi.");
          return;
      }
      try {
          const nowShort = format(new Date(), "HH:mm");
          const recordValue = `${nowShort} (Haid)`;
          const payload = { ...record, status: 'Haid', checkIn: recordValue, duha: recordValue, zuhur: recordValue, ashar: recordValue };
          if (!isMockMode && db) await db.collection("attendance").doc(record.id).set(payload, { merge: true });
          toast.success(`${record.studentName} dicatat Haid`);
      } catch (e) { toast.error("Gagal mencatat status."); }
  };

  const handleExportPDF = async () => {
    if (loading) { toast.error("Memuat data..."); return; }
    if (displayData.length === 0) { toast.error("Tidak ada data."); return; }
    const toastId = toast.loading("Membangun Dokumen PDF...");

    try {
        const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
        const pageWidth = doc.internal.pageSize.getWidth();
        const centerX = pageWidth / 2;
        const margin = 15;

        doc.setFont("helvetica", "bold"); doc.setFontSize(10);
        doc.text("KEMENTERIAN AGAMA REPUBLIK INDONESIA", centerX + 8, 14, { align: "center" });
        doc.setFontSize(12);
        doc.text((madrasahInfo?.nama || "MAN 1 HULU SUNGAI TENGAH").toUpperCase(), centerX + 8, 24, { align: "center" });
        doc.setLineWidth(0.6); doc.line(margin, 30, pageWidth - margin, 30);

        autoTable(doc, {
            startY: 40,
            head: [['NO', 'ID UNIK', 'NAMA LENGKAP SISWA', 'KLS', 'MSK', 'DHA', 'ZHR', 'ASR', 'PLG', 'ST']],
            body: displayData.map((r, i) => [
                i + 1, r.idUnik || '-', (r.studentName || '').toUpperCase(), (r.class || '').replace('IPA ', '').replace('IPS ', ''),
                (r.checkIn || '-').substring(0, 12), (r.duha || '-').substring(0, 12), (r.zuhur || '-').substring(0, 12), (r.ashar || '-').substring(0, 12), (r.checkOut || '-').substring(0, 5),
                r.status === 'Alpha' ? 'A' : r.status === 'Haid' ? 'HD' : 'H'
            ]),
            headStyles: { fillColor: [43, 58, 85], halign: 'center', fontSize: 6.5, textColor: [255, 255, 255] },
            styles: { fontSize: 6.5, font: 'helvetica', cellPadding: 1.5 },
            didParseCell: (data) => {
                if (data.section === 'body') {
                    const text = String(data.cell.raw || '');
                    if (text.includes('(Haid)') || text === 'HD') {
                        data.cell.styles.textColor = [220, 38, 38]; // Warna Merah
                    }
                }
            }
        });

        doc.save(`PRESENSI_SEMUA_SISWA_${format(date, 'yyyyMMdd')}.pdf`);
        toast.success("PDF Berhasil Dibuat", { id: toastId });
    } catch (e) { toast.error("Gagal mencetak laporan PDF."); }
  };

  const SessionPill = ({ label, time, color }: { label: string, time: string | null, color: string }) => {
      const isHaidString = String(time).includes('(Haid)');
      const isFilled = !!time;
      const activeColorClass = isHaidString ? 'text-rose-600' : `text-${color}-600`;
      const activeBgClass = isHaidString ? 'bg-rose-50 border-rose-200 dark:bg-rose-900/20' : `bg-${color}-50/50 dark:bg-${color}-900/10 border-${color}-100`;

      return (
        <div className={`flex-1 flex flex-col items-center gap-1 p-2 rounded-2xl border transition-all ${
            isFilled ? activeBgClass : 'bg-slate-50/30 dark:bg-slate-900/30 border-slate-100 opacity-40'
        }`}>
            <span className={`text-[6px] font-black uppercase tracking-tighter ${isFilled ? activeColorClass : 'text-slate-400'}`}>{isHaidString ? 'HAID' : label}</span>
            <span className={`text-[10px] font-mono font-black ${isFilled ? `${activeColorClass} ${isHaidString ? 'animate-pulse' : ''}` : 'text-slate-300'}`}>
                {isFilled ? time?.substring(0, 12) : '--:--'}
            </span>
        </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-[#f8fafc] dark:bg-[#020617] overflow-hidden">
      <div className="bg-white/80 dark:bg-[#0B1121]/90 backdrop-blur-xl px-5 py-4 flex items-center justify-between z-40 sticky top-0 border-b border-slate-100 dark:border-slate-800 safe-pt">
          <div className="flex items-center gap-4">
              <button onClick={onBack} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-500 active:scale-90"><ArrowLeftIcon className="w-5 h-5" /></button>
              <div><h2 className="font-black text-slate-900 dark:text-white text-sm uppercase tracking-tight">Daftar Presensi</h2></div>
          </div>
          <div className="flex gap-2">
              <button onClick={handleExportPDF} className="p-2.5 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-xl"><PrinterIcon className="w-5 h-5" /></button>
              <button onClick={() => onNavigate(ViewState.SCANNER)} className="p-2.5 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-500/30"><CameraIcon className="w-5 h-5" /></button>
          </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar p-5 lg:p-8 space-y-6 pb-32 max-w-4xl mx-auto">
          <div className="bg-white dark:bg-[#151E32] p-6 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm">
              <div className="flex flex-col sm:flex-row gap-4 items-center justify-between">
                  <div className="flex items-center gap-4 bg-slate-50 dark:bg-slate-900/50 p-1.5 rounded-2xl border border-slate-100 dark:border-slate-800 w-full sm:w-auto">
                      <button onClick={() => setDate(new Date(date.getTime() - 86400000))} className="p-2.5 rounded-xl transition-all active:scale-90"><ChevronLeft className="w-4 h-4 text-slate-400"/></button>
                      <div className="flex-1 text-center min-w-[140px]"><h3 className="text-xs font-black text-slate-800 dark:text-white uppercase tracking-widest">{format(date, "dd MMMM yyyy", { locale: localeID })}</h3></div>
                      <button onClick={() => setDate(new Date(date.getTime() + 86400000))} className="p-2.5 rounded-xl transition-all active:scale-90"><ChevronRight className="w-4 h-4 text-slate-400"/></button>
                  </div>
                  <button onClick={() => setIsHaidMode(!isHaidMode)} className={`flex items-center gap-2 px-6 py-4 rounded-2xl text-[9px] font-black uppercase transition-all border shadow-sm active:scale-95 ${isHaidMode ? 'bg-rose-600 border-rose-400 text-white' : 'bg-white dark:bg-slate-800 border-slate-200 text-slate-400'}`}><HeartIcon className="w-4 h-4" /><span>Quick Haid</span></button>
              </div>
          </div>

          <div className="space-y-4">
              {loading ? (
                  <div className="py-20 text-center flex flex-col items-center gap-3"><Loader2 className="w-10 h-10 animate-spin text-indigo-500 opacity-20" /></div>
              ) : displayData.length > 0 ? (
                  displayData.map((record) => (
                  <div key={record.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm group relative overflow-hidden transition-all hover:shadow-lg">
                      <div className={`absolute top-0 left-0 w-1.5 h-full ${record.status === 'Haid' ? 'bg-rose-500' : 'bg-slate-50 dark:bg-slate-800'}`}></div>
                      <div className="flex items-start justify-between mb-6 pl-2">
                          <div className="flex items-center gap-4 min-w-0 flex-1">
                              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-lg shrink-0 border-2 ${record.status === 'Haid' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100'}`}>{record.status === 'Haid' ? <HeartIcon className="w-7 h-7 fill-current" /> : (record.studentName || '?').charAt(0)}</div>
                              <div className="min-w-0">
                                  <h4 className={`font-black text-sm uppercase truncate ${record.status === 'Haid' ? 'text-rose-600' : 'text-slate-800 dark:text-white'}`}>{record.studentName}</h4>
                                  <div className="flex items-center gap-2 mt-1.5">
                                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{record.class || '-'}</span>
                                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-md ${record.status === 'Haid' ? 'text-rose-600 bg-rose-50' : 'text-slate-400 bg-slate-100'}`}>{record.status}</span>
                                  </div>
                              </div>
                          </div>
                          <button onClick={() => handleEditClick(record)} className={`p-3 rounded-2xl transition-all ${isHaidMode ? 'bg-rose-50 text-rose-600' : 'bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-indigo-600 opacity-0 group-hover:opacity-100'}`}>{isHaidMode ? <HeartIcon className="w-5 h-5 fill-current animate-pulse" /> : <PencilIcon className="w-4 h-4" />}</button>
                      </div>
                      <div className="flex gap-2.5 pl-2 cursor-pointer" onClick={() => handleEditClick(record)}>
                          <SessionPill label="MSK" time={record.checkIn} color="emerald" />
                          <SessionPill label="DHA" time={record.duha} color="violet" />
                          <SessionPill label="ZHR" time={record.zuhur} color="blue" />
                          <SessionPill label="ASR" time={record.ashar} color="amber" />
                          <SessionPill label="PLG" time={record.checkOut} color="rose" />
                      </div>
                  </div>
                  ))
              ) : (
                <div className="py-20 text-center bg-white dark:bg-[#151E32] rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800"><Search className="w-12 h-12 text-slate-100 dark:text-slate-800 mx-auto mb-4" /><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tidak ada data siswa ditemukan</p></div>
              )}
          </div>
      </div>

      {isModalOpen && editingRecord && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-xs rounded-[3rem] p-8 shadow-2xl border border-white/10">
                  <h3 className="font-black text-xs text-slate-800 dark:text-white uppercase mb-8 text-center tracking-widest">Koreksi Data</h3>
                  <div className="space-y-5">
                      <select 
                        value={editingRecord.status} 
                        onChange={async (e) => {
                            const newStatus = e.target.value as any;
                            if (!isMockMode && db) await db.collection("attendance").doc(editingRecord.id).set({ ...editingRecord, status: newStatus }, { merge: true });
                            setIsModalOpen(false);
                        }}
                        className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none"
                      >
                          <option value="Hadir">HADIR</option>
                          <option value="Haid">HAID</option>
                          <option value="Sakit">SAKIT</option>
                          <option value="Izin">IZIN</option>
                          <option value="Alpha">ALPA</option>
                      </select>
                      <button onClick={() => setIsModalOpen(false)} className="w-full py-4 bg-slate-100 text-slate-500 rounded-2xl text-[9px] font-black uppercase tracking-widest">Tutup</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

export default Presensi;

