                  <button onClick={() => setIsHaidMode(!isHaidMode)} className={`flex items-center justify-center gap-2 px-6 py-4 rounded-2xl text-[9px] font-black uppercase transition-all border shadow-sm active:scale-95 w-full md:w-auto shrink-0 ${isHaidMode ? 'bg-rose-600 border-rose-400 text-white' : 'bg-white dark:bg-slate-800 border-slate-200 text-slate-400'}`}>
                    <HeartIcon className={`w-4 h-4 ${isHaidMode ? 'fill-current' : ''}`} />
