                  <form onSubmit={handleSaveCorrection} className="space-y-6">
                      <div className="space-y-1.5">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1 tracking-widest">Nama Peserta Didik</label>
                          <div className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black text-indigo-600">{editingRecord.studentName}</div>
                      </div>

                      <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1 tracking-widest">Status Kehadiran</label>
                        <select 
                            value={editingRecord.status} 
                            onChange={(e) => setEditingRecord({ ...editingRecord, status: e.target.value as any })}
                            className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none"
