                                    <div className="flex items-center gap-2 mt-2">
                                        <span className={`px-2 py-0.5 rounded-md text-[7px] font-black uppercase ${r.status === 'Hadir' ? 'bg-emerald-50 text-emerald-600' : r.status === 'Haid' ? 'bg-rose-50 text-rose-600' : 'bg-slate-100 text-slate-500'}`}>{r.status}</span>
                                        <span className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">{r.class || '-'}</span>
