                                <div className="text-right hidden sm:block">
                                    <p className="text-[12px] font-mono font-black text-slate-800 dark:text-white">{(r.checkIn || '--:--').substring(0, 5)}</p>
                                    <p className="text-[8px] font-black text-slate-400 uppercase">Jam Masuk</p>
                                </div>
                                {!isStudent && (
                                    <div className="flex gap-1.5">
                                        <button onClick={() => handleEditClick(r)} className="p-3 bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-indigo-600 rounded-xl transition-all shadow-sm"><PencilIcon className="w-4 h-4" /></button>
                                        <button onClick={() => handleDeleteRecord(r)} className="p-3 bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-rose-600 rounded-xl transition-all shadow-sm"><TrashIcon className="w-4 h-4" /></button>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
