                </div>
            )}
        </div>
      </div>

      {isEditModalOpen && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-sm rounded-[3rem] p-8 shadow-2xl border border-white/10 animate-in zoom-in duration-300 overflow-hidden">
                  <h3 className="font-black text-sm text-slate-800 dark:text-white uppercase mb-8 text-center tracking-[0.2em]">Koreksi Kehadiran</h3>

                  <form onSubmit={handleSaveEdit} className="space-y-6">
