                        <select 
                            value={editForm.status} 
                            onChange={(e) => setEditForm({...editForm, status: e.target.value as any})} 
                            className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none shadow-inner"
