export default AttendanceHistory;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './Layout';
import { db, auth, isMockMode } from '../services/firebase';
import { 
  CalendarIcon, CheckCircleIcon, XCircleIcon, ClockIcon, Search, ArrowPathIcon,
  PencilIcon, TrashIcon, PrinterIcon, ChartBarIcon, Loader2, HeartIcon, SparklesIcon,
  UserIcon, UsersGroupIcon, ArrowRightIcon, ShieldCheckIcon, SaveIcon, BookOpenIcon,
  ChevronDownIcon
} from './Icons';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ViewState, AttendanceStatus, Student, UserRole, AttendanceRecord } from '../types';

interface AttendanceHistoryProps {
  onBack: () => void;
  onNavigate: (view: ViewState) => void;
  userRole: UserRole;
}

const AttendanceHistory: React.FC<AttendanceHistoryProps> = ({ onBack, onNavigate, userRole }) => {
  const [selectedDate, setSelectedDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [selectedClass, setSelectedClass] = useState<string>('All');
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [records, setRecords] = useState<AttendanceRecord[]>([]);
  const [classes, setClasses] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);
  const [editForm, setEditForm] = useState({
      status: 'Hadir' as AttendanceStatus,
      checkIn: '',
      duha: '',
      zuhur: '',
      ashar: '',
      checkOut: ''
  });

  const isStudent = userRole === UserRole.SISWA;

  useEffect(() => {
    if (isMockMode) {
        setClasses(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
        return;
    }
    if (db) {
        db.collection('classes').get().then(s => setClasses(s.docs.map(d => d.data().name).sort()));
    }
  }, []);

  useEffect(() => {
    setLoading(true);

    if (isMockMode) {
        setTimeout(() => {
            setRecords([
                { 
                    id: 'm1', studentId: 's1', studentName: 'ADELIA SRI SUNDARI', 
                    class: 'XII IPA 1', status: 'Hadir', date: selectedDate, 
                    checkIn: '07:15:00', duha: '08:20:00', zuhur: '12:30:00', ashar: null, checkOut: null 
                } as any
            ]);
            setLoading(false);
        }, 500);
        return;
    }

    if (!db || !auth.currentUser) return;

    let query = db.collection('attendance').where('date', '==', selectedDate);
    if (isStudent) query = query.where('studentId', '==', auth.currentUser.uid);
    else if (selectedClass !== 'All') query = query.where('class', '==', selectedClass);

    const unsubscribe = query.onSnapshot(snapshot => {
        const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as AttendanceRecord));
        data.sort((a, b) => (a.studentName || '').localeCompare(b.studentName || ''));
        setRecords(data);
        setLoading(false);
    }, err => {
        console.error(err);
        setLoading(false);
    });
    return () => unsubscribe();
  }, [selectedDate, selectedClass, isStudent]);

  const filteredRecords = useMemo(() => {
      const q = searchQuery.toLowerCase().trim();
      return records.filter(r => {
          const matchesSearch = q === '' || 
                               String(r.studentName || '').toLowerCase().includes(q) ||
                               String((r as any).idUnik || '').toLowerCase().includes(q);
          const matchesStatus = filterStatus === 'All' || r.status === filterStatus;
          return matchesSearch && matchesStatus;
      });
  }, [records, searchQuery, filterStatus]);

  const handleEditClick = (record: AttendanceRecord) => {
      setEditingRecord(record);
      setEditForm({ 
          status: record.status || 'Hadir', 
          checkIn: record.checkIn ? record.checkIn.substring(0, 5) : '', 
          duha: record.duha ? record.duha.substring(0, 5) : '', 
          zuhur: record.zuhur ? record.zuhur.substring(0, 5) : '', 
          ashar: record.ashar ? record.ashar.substring(0, 5) : '', 
          checkOut: record.checkOut ? record.checkOut.substring(0, 5) : '' 
      });
      setIsEditModalOpen(true);
  };

  const handleDeleteRecord = async (record: AttendanceRecord) => {
      if (!window.confirm(`Hapus data presensi ${record.studentName} secara permanen dari database?`)) return;

      const toastId = toast.loading("Menghapus data...");
      try {
          if (!isMockMode && db) {
              await db.collection('attendance').doc(record.id).delete();
          } else if (isMockMode) {
              setRecords(prev => prev.filter(r => r.id !== record.id));
          }
          toast.success("Data berhasil dihapus", { id: toastId });
      } catch (e) {
          toast.error("Gagal menghapus data dari server", { id: toastId });
      }
  };

  const handleSaveEdit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingRecord) return;

      setSaving(true);
      const toastId = toast.loading("Menyimpan koreksi...");
      try {
          const payload = {
              status: editForm.status,
              checkIn: editForm.checkIn ? `${editForm.checkIn}:00` : null,
              duha: editForm.duha ? `${editForm.duha}:00` : null,
              zuhur: editForm.zuhur ? `${editForm.zuhur}:00` : null,
              ashar: editForm.ashar ? `${editForm.ashar}:00` : null,
              checkOut: editForm.checkOut ? `${editForm.checkOut}:00` : null
          };

          if (!isMockMode && db) {
              await db.collection('attendance').doc(editingRecord.id).update(payload);
          } else if (isMockMode) {
              setRecords(prev => prev.map(r => r.id === editingRecord.id ? { ...r, ...payload } : r));
          }

          toast.success("Data riwayat diperbarui", { id: toastId });
          setIsEditModalOpen(false);
      } catch (e) {
          toast.error("Gagal memperbarui database", { id: toastId });
      } finally {
          setSaving(false);
      }
  };

  return (
    <Layout title="Riwayat Absensi" subtitle={isStudent ? "Kehadiran Personal" : "Manajemen Log Database"} icon={CalendarIcon} onBack={onBack}>
      <div className="p-4 lg:p-6 pb-32 space-y-6">

        {/* Filters Panel */}
        <div className="bg-white dark:bg-[#151E32] p-6 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm space-y-5">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Tanggal</label>
                    <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-inner" />
                </div>
                {!isStudent && (
                    <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Filter Rombel</label>
                        <div className="relative group">
                            <select value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none appearance-none cursor-pointer shadow-inner">
                                <option value="All">SEMUA KELAS</option>
                                {classes.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                    </div>
                )}
            </div>

            <div className="relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input 
                    type="text" 
                    placeholder="Cari Nama atau ID Unik Siswa..." 
                    value={searchQuery}
                    onChange={e => setSearchQuery(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 bg-slate-50 dark:bg-slate-900 border border-transparent focus:border-indigo-100 rounded-2xl text-xs font-bold shadow-inner outline-none transition-all"
                />
            </div>

            {!isStudent && (
                <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
                    {['All', 'Hadir', 'Sakit', 'Izin', 'Alpha', 'Haid'].map(s => (
                        <button 
                            key={s} 
                            onClick={() => setFilterStatus(s)} 
                            className={`px-6 py-2.5 rounded-xl text-[9px] font-black uppercase transition-all border whitespace-nowrap ${filterStatus === s ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-500/20' : 'bg-slate-50 dark:bg-slate-900 text-slate-400 border-slate-100 dark:border-slate-800'}`}
                        >
                            {s}
                        </button>
                    ))}
                </div>
            )}
        </div>

        {/* List Content */}
        <div className="space-y-4">
            {loading ? (
                <div className="py-20 text-center flex flex-col items-center gap-3"><Loader2 className="w-10 h-10 animate-spin text-indigo-500 opacity-20" /><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Memuat Log...</p></div>
            ) : filteredRecords.length > 0 ? (
                <div className="grid grid-cols-1 gap-4">
                    {filteredRecords.map((r) => (
                        <div key={r.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col sm:flex-row sm:items-center justify-between group relative overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-500">
                            <div className={`absolute top-0 left-0 w-1.5 h-full ${r.status === 'Haid' ? 'bg-rose-500' : r.status === 'Hadir' ? 'bg-emerald-500' : 'bg-slate-300'}`}></div>

                            <div className="flex items-center gap-4 flex-1 min-w-0 mb-4 sm:mb-0">
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-lg shrink-0 border-2 transition-transform group-hover:scale-105 ${r.status === 'Haid' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100'}`}>
                                    {(r.studentName || '?').charAt(0)}
                                </div>
                                <div className="min-w-0">
                                    <h4 className="font-black text-xs uppercase truncate tracking-tight text-slate-800 dark:text-white leading-none mb-2">{r.studentName}</h4>
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase ${r.status === 'Hadir' ? 'bg-emerald-50 text-emerald-600' : r.status === 'Haid' ? 'bg-rose-50 text-rose-600' : 'bg-slate-100 text-slate-500'}`}>{r.status}</span>
                                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{r.class || '-'}</span>
                                    </div>
                                </div>
                            </div>

                            <div className="flex items-center justify-between sm:justify-end gap-6 pl-2 sm:pl-0 border-t sm:border-0 border-slate-50 dark:border-slate-800 pt-4 sm:pt-0">
                                <div className="flex flex-col items-center">
                                    <p className="text-[12px] font-mono font-black text-slate-800 dark:text-white">{(r.checkIn || '--:--').substring(0, 5)}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Masuk</p>
                                </div>
                                <div className="flex flex-col items-center">
                                    <p className="text-[12px] font-mono font-black text-slate-800 dark:text-white">{(r.checkOut || '--:--').substring(0, 5)}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Pulang</p>
                                </div>

                                {!isStudent && (
                                    <div className="flex gap-2 ml-4">
                                        <button onClick={() => handleEditClick(r)} className="p-3 bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-indigo-600 rounded-2xl transition-all shadow-sm active:scale-90" title="Edit Riwayat"><PencilIcon className="w-4 h-4" /></button>
                                        <button onClick={() => handleDeleteRecord(r)} className="p-3 bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-rose-600 rounded-2xl transition-all shadow-sm active:scale-90" title="Hapus Permanen"><TrashIcon className="w-4 h-4" /></button>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="py-24 text-center bg-white dark:bg-[#151E32] rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
                    <Search className="w-12 h-12 text-slate-100 dark:text-slate-800 mx-auto mb-4" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Belum Ada Data</p>
                </div>
            )}
        </div>
      </div>

      {/* Full Edit Modal */}
      {isEditModalOpen && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-sm rounded-[3rem] p-8 shadow-2xl border border-white/10 animate-in zoom-in duration-300 max-h-[90vh] overflow-y-auto scrollbar-hide">
                  <div className="text-center mb-8">
                      <h3 className="font-black text-sm text-slate-800 dark:text-white uppercase tracking-[0.2em]">Koreksi Kehadiran</h3>
                      <p className="text-[9px] font-bold text-indigo-500 mt-2 truncate">{(editingRecord?.studentName || '').toUpperCase()}</p>
                  </div>

                  <form onSubmit={handleSaveEdit} className="space-y-6">
                      <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1 tracking-widest">Status Presensi</label>
                        <div className="relative group">
                            <select 
                                value={editForm.status} 
                                onChange={(e) => setEditForm({...editForm, status: e.target.value as AttendanceStatus})} 
                                className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none shadow-inner appearance-none cursor-pointer"
                            >
                                <option value="Hadir">HADIR</option>
                                <option value="Haid">HAID (Siklus Bulanan)</option>
                                <option value="Sakit">SAKIT</option>
                                <option value="Izin">IZIN / DISPENSASI</option>
                                <option value="Alpha">ALPHA / TANPA KET.</option>
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-1.5">
                              <label className="text-[8px] font-black text-slate-400 uppercase ml-1 tracking-widest">Jam Masuk</label>
                              <input type="time" value={editForm.checkIn} onChange={e => setEditForm({...editForm, checkIn: e.target.value})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black shadow-inner" />
