                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Duha</label>
                                <input type="time" value={editForm.duha} onChange={e => setEditForm({...editForm, duha: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
