import React, { useState, useEffect, useMemo } from 'react';
import { deleteStudent, updateStudent, addStudent } from '../services/studentService';
import { Student, UserRole } from '../types';
import { db, auth, isMockMode } from '../services/firebase';
import { toast } from 'sonner';
import Layout from './Layout';
import { 
  UsersGroupIcon, 
  PencilIcon, TrashIcon, Search, PlusIcon,
  Loader2, XCircleIcon, SaveIcon, UserIcon,
  AcademicCapIcon, PhoneIcon,
  EnvelopeIcon, MapPinIcon, ChevronDownIcon,
  SparklesIcon, IdentificationIcon, CalendarIcon,
  BriefcaseIcon, HeartIcon
} from './Icons';

const StudentData: React.FC<{ onBack: () => void, userRole: UserRole }> = ({ onBack, userRole }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [classList, setClassList] = useState<string[]>([]);

  const initialFormState: Partial<Student> = {
    namaLengkap: '',
    nisn: '',
    idUnik: '',
    nik: '',
    email: '',
    userlogin: '',
    tempatLahir: '',
    tanggalLahir: '',
    tingkatRombel: '',
    status: 'Aktif',
    jenisKelamin: 'Laki-laki',
    noTelepon: '',
    alamat: '',
    namaAyahKandung: '',
    namaIbuKandung: '',
    namaWali: ''
  };

  const [formData, setFormData] = useState<Partial<Student>>(initialFormState);

  // Load class list for form selection only
  useEffect(() => {
    if (isMockMode) {
      setClassList(['X IPA 1', 'XI IPS 1', 'XII AGAMA']);
      return;
    }
    if (db) {
      db.collection('classes').get().then(snap => {
        setClassList(snap.docs.map(d => d.data().name).sort());
      }).catch(e => console.warn("Firestore permissions: classList", e.message));
    }
  }, []);

  // Fetch ALL students from database
  useEffect(() => {
    setLoading(true);
    if (isMockMode) {
        setTimeout(() => {
            setStudents([
                { id: 'm1', namaLengkap: 'DIENDE ADELLYA AQILLA', nisn: '0086806447', idUnik: '15012', email: 'adella@imam.sch.id', userlogin: 'adella.aqilla', tingkatRombel: 'XII IPA 1', status: 'Aktif', jenisKelamin: 'Perempuan' } as Student,
                { id: 'm2', namaLengkap: 'AHMAD DAHLAN', nisn: '0011223344', idUnik: '15015', email: 'dahlan@gmail.com', userlogin: 'dahlan.88', tingkatRombel: '', status: 'Aktif', jenisKelamin: 'Laki-laki' } as Student
            ]);
            setLoading(false);
        }, 1000);
        return;
    }
    if (!db) return;

    // Query seluruh database (Limit 500 untuk performa mobile)
    const unsubscribe = db.collection('students')
        .orderBy('namaLengkap')
        .limit(500)
        .onSnapshot(
            snapshot => {
                setStudents(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student)));
                setLoading(false);
            }, 
            err => {
                console.warn("Student fetch denied:", err.message);
                setLoading(false);
            }
        );
    return () => unsubscribe();
  }, []);

  // Enhanced Search Logic
  const processedStudents = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    const list = [...students];

    if (!query) {
        return list.sort((a, b) => (a.namaLengkap || '').localeCompare(b.namaLengkap || ''));
    }

    return list.filter(s => 
        String(s.namaLengkap || '').toLowerCase().includes(query) || 
        String(s.nisn || '').toLowerCase().includes(query) ||
        String(s.idUnik || '').toLowerCase().includes(query) ||
        String(s.email || '').toLowerCase().includes(query) ||
        String(s.userlogin || '').toLowerCase().includes(query)
    ).sort((a, b) => (a.namaLengkap || '').localeCompare(b.namaLengkap || ''));
  }, [students, searchQuery]);

  const handleAddNew = () => { 
    setEditingId(null); 
    setFormData({ ...initialFormState }); 
    setIsModalOpen(true); 
  };

  const handleEdit = (student: Student) => { 
    setEditingId(student.id || null); 
    setFormData({ ...student }); 
    setIsModalOpen(true); 
  };

  const handleDelete = async (student: Student) => {
      if (!student.id) return;
      if (window.confirm(`Hapus permanen data siswa ${student.namaLengkap}? Tindakan ini tidak dapat dibatalkan.`)) {
          const toastId = toast.loading("Menghapus data...");
          try { 
              await deleteStudent(student.id); 
              toast.success("Data berhasil dihapus.", { id: toastId }); 
          } catch (e) { 
              toast.error("Gagal menghapus data.", { id: toastId }); 
          }
      }
  };

  const handleSave = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!formData.namaLengkap || !formData.nisn) {
          toast.error("Nama dan NISN wajib diisi.");
          return;
      }
      setSaving(true);
      const toastId = toast.loading("Menyimpan data...");
      try {
          if (editingId) { 
              await updateStudent(editingId, formData); 
              toast.success("Profil siswa diperbarui.", { id: toastId }); 
          }
          else { 
              await addStudent(formData as Student); 
              toast.success("Siswa baru berhasil ditambahkan.", { id: toastId }); 
          }
          setIsModalOpen(false);
      } catch (e) { 
          toast.error("Gagal menyimpan data."); 
      } finally { 
          setSaving(false); 
      }
  };

  const canManage = userRole === UserRole.ADMIN || userRole === UserRole.DEVELOPER;

  return (
    <Layout title="Master Data Siswa" subtitle="Database Induk Terpusat" icon={UsersGroupIcon} onBack={onBack}>
      <div className="p-4 lg:p-8 pb-32 space-y-6">

        {/* Search Header - Filter Rombel Dihapus */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col sm:flex-row gap-4">
            <div className="relative group flex-1">
                <Search className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input 
                    type="text" 
                    placeholder="Cari Nama, NISN, ID Unik, Email, atau Login..." 
                    value={searchQuery} 
                    onChange={(e) => setSearchQuery(e.target.value)} 
                    className="w-full bg-slate-50 dark:bg-slate-900 border border-transparent rounded-[1.5rem] py-4 pl-12 pr-4 text-xs font-bold outline-none text-slate-800 dark:text-white shadow-inner focus:bg-white transition-all" 
                />
            </div>
            {canManage && (
                <button 
                    onClick={handleAddNew} 
                    disabled={loading}
                    className={`px-8 py-4 rounded-[1.5rem] text-[10px] font-black uppercase flex items-center justify-center gap-2 transition-all ${loading ? 'bg-slate-100 text-slate-400 cursor-not-allowed' : 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 active:scale-95'}`}
                >
                    <PlusIcon className="w-4 h-4" /> Tambah Siswa
                </button>
            )}
        </div>

        {/* Info Stats */}
        {!loading && (
            <div className="flex items-center justify-between px-2">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Menampilkan {processedStudents.length} dari {students.length} Data</p>
                <div className="flex items-center gap-1.5 px-2.5 py-1 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-lg border border-indigo-100 dark:border-indigo-800">
                    <SparklesIcon className="w-3 h-3" />
                    <span className="text-[8px] font-black uppercase">Master Sync</span>
                </div>
            </div>
        )}

        {/* Content Area */}
        {loading ? (
            <div className="text-center py-24 flex flex-col items-center gap-4">
                <Loader2 className="w-12 h-12 animate-spin text-indigo-500 opacity-20" />
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] animate-pulse">Sinkronisasi Database...</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in duration-700">
                {processedStudents.map((s) => (
                    <div key={s.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.2rem] border border-slate-100 dark:border-slate-800 shadow-sm flex justify-between items-center group transition-all hover:shadow-xl hover:border-indigo-100 dark:hover:border-indigo-900/50">
                        <div className="flex items-center gap-4 min-w-0">
                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-base border shadow-sm shrink-0 transition-transform group-hover:scale-110 ${s.jenisKelamin === 'Perempuan' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                                {(s.namaLengkap || '?').charAt(0)}
                            </div>
                            <div className="min-w-0">
                                <h4 className="font-black text-slate-800 dark:text-white text-[11px] uppercase truncate leading-tight">{s.namaLengkap}</h4>
                                <div className="flex flex-wrap items-center gap-2 mt-1.5">
                                    <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded tracking-tighter ${s.tingkatRombel ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400' : 'bg-rose-50 dark:bg-rose-900/30 text-rose-600 dark:text-rose-400'}`}>
                                        {s.tingkatRombel || 'TANPA ROMBEL'}
                                    </span>
                                    <span className="text-[9px] font-mono font-bold text-slate-400">{s.nisn}</span>
                                </div>
                            </div>
                        </div>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                            <button onClick={() => handleEdit(s)} className="p-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-indigo-600 hover:bg-white transition-all shadow-sm"><PencilIcon className="w-4 h-4"/></button>
                            <button onClick={() => handleDelete(s)} className="p-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-rose-600 hover:bg-white transition-all shadow-sm"><TrashIcon className="w-4 h-4"/></button>
                        </div>
                    </div>
                ))}
                {processedStudents.length === 0 && (
                    <div className="col-span-full py-20 text-center bg-white dark:bg-[#151E32] rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800">
                         <Search className="w-12 h-12 text-slate-100 dark:text-slate-800 mx-auto mb-4" />
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tidak ada siswa yang cocok</p>
                    </div>
                )}
            </div>
        )}
      </div>

      {/* FORM MODAL */}
      {isModalOpen && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-2xl rounded-[2.5rem] shadow-2xl animate-in zoom-in duration-300 flex flex-col max-h-[90vh] border border-white/10 relative overflow-hidden">

                  {/* Modal Header */}
                  <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-[#0B1121] z-10">
                      <div>
                          <h3 className="text-lg font-black text-slate-800 dark:text-white uppercase leading-none">{editingId ? 'Edit Profil Siswa' : 'Registrasi Siswa Baru'}</h3>
                          <p className="text-[9px] font-bold text-indigo-500 uppercase mt-2 tracking-widest">Update Informasi Master Database</p>
                      </div>
                      <button onClick={() => setIsModalOpen(false)} className="p-2.5 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
                          <XCircleIcon className="w-8 h-8" />
                      </button>
                  </div>

                  {/* Modal Body */}
                  <div className="p-6 lg:p-8 overflow-y-auto custom-scrollbar flex-1 space-y-8 pb-12">
                      <form id="studentForm" onSubmit={handleSave} className="space-y-10">

                          <div className="space-y-5">
                              <h5 className="text-[9px] font-black text-indigo-500 uppercase tracking-[0.3em] flex items-center gap-2 border-b border-indigo-50 dark:border-indigo-900/30 pb-2">
                                  <IdentificationIcon className="w-3.5 h-3.5" /> Data Identitas & Login
                              </h5>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                  <div className="space-y-1.5 md:col-span-2">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Lengkap *</label>
                                      <input required type="text" value={formData.namaLengkap || ''} onChange={e => setFormData({...formData, namaLengkap: (e.target.value || '').toUpperCase()})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-inner" placeholder="NAMA LENGKAP" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">NISN *</label>
                                      <input required type="text" value={formData.nisn || ''} onChange={e => setFormData({...formData, nisn: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">ID Unik Lokal</label>
                                      <input type="text" value={formData.idUnik || ''} onChange={e => setFormData({...formData, idUnik: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">User Login / Username</label>
                                      <input type="text" value={formData.userlogin || ''} onChange={e => setFormData({...formData, userlogin: e.target.value.toLowerCase()})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" placeholder="username.siswa" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
                                      <input type="email" value={formData.email || ''} onChange={e => setFormData({...formData, email: e.target.value.toLowerCase()})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" placeholder="email@imam.id" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Rombel / Kelas</label>
                                      <div className="relative">
                                          <select value={formData.tingkatRombel || ''} onChange={e => setFormData({...formData, tingkatRombel: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold appearance-none cursor-pointer">
                                              <option value="">-- TANPA ROMBEL --</option>
                                              {classList.map(c => <option key={c} value={c}>{c}</option>)}
                                          </select>
                                          <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                                      </div>
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Status</label>
                                      <select value={formData.status || 'Aktif'} onChange={e => setFormData({...formData, status: e.target.value as any})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold">
                                          <option value="Aktif">Aktif</option>
                                          <option value="Lulus">Lulus</option>
                                          <option value="Mutasi">Mutasi</option>
                                          <option value="Nonaktif">Nonaktif</option>
                                      </select>
                                  </div>
                              </div>
                          </div>

                          <div className="space-y-5">
                              <h5 className="text-[9px] font-black text-emerald-500 uppercase tracking-[0.3em] flex items-center gap-2 border-b border-emerald-50 dark:border-emerald-900/30 pb-2">
                                  <UserIcon className="w-3.5 h-3.5" /> Profil Personal
                              </h5>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Jenis Kelamin</label>
                                      <div className="grid grid-cols-2 gap-2">
                                          <button type="button" onClick={() => setFormData({...formData, jenisKelamin: 'Laki-laki'})} className={`py-3.5 rounded-xl border text-[10px] font-black uppercase transition-all ${formData.jenisKelamin === 'Laki-laki' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-400'}`}>Laki-laki</button>
                                          <button type="button" onClick={() => setFormData({...formData, jenisKelamin: 'Perempuan'})} className={`py-3.5 rounded-xl border text-[10px] font-black uppercase transition-all ${formData.jenisKelamin === 'Perempuan' ? 'bg-rose-600 border-rose-600 text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-400'}`}>Perempuan</button>
                                      </div>
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">No. WhatsApp</label>
                                      <input type="text" value={formData.noTelepon || ''} onChange={e => setFormData({...formData, noTelepon: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" />
                                  </div>
                              </div>
                          </div>
                      </form>
                  </div>

                  {/* Modal Footer */}
                  <div className="p-6 border-t border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-[#0B1121] flex gap-4 z-10">
                      <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 bg-white dark:bg-slate-800 text-slate-500 font-black rounded-2xl border border-slate-200 dark:border-slate-700 active:scale-95 transition-all text-[10px] uppercase tracking-widest shadow-sm">Batal</button>
                      <button type="submit" form="studentForm" disabled={saving} className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white font-black py-4 rounded-2xl shadow-2xl shadow-indigo-500/20 transition-all flex items-center justify-center gap-3 active:scale-[0.98] disabled:opacity-50">
                        {saving ? <Loader2 className="w-5 h-5 animate-spin" /> : <SaveIcon className="w-5 h-5" />}
                        <span className="uppercase tracking-[0.2em] text-[10px]">{editingId ? 'SIMPAN PERUBAHAN' : 'DAFTARKAN SISWA'}</span>
                      </button>
                  </div>
              </div>
          </div>
      )}
    </Layout>
  );
};

export default StudentData;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './Layout';
import { db, auth, isMockMode } from '../services/firebase';
import { 
  CalendarIcon, CheckCircleIcon, ClockIcon, Search, 
  PencilIcon, TrashIcon, Loader2, HeartIcon, 
  SaveIcon, ChevronDownIcon, ArrowLeftIcon, BookOpenIcon
} from './Icons';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ViewState, AttendanceStatus, UserRole, AttendanceRecord, Student } from '../types';

interface AttendanceHistoryProps {
  onBack: () => void;
  onNavigate: (view: ViewState) => void;
  userRole: UserRole;
}

const AttendanceHistory: React.FC<AttendanceHistoryProps> = ({ onBack, onNavigate, userRole }) => {
  const [selectedDate, setSelectedDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [selectedClass, setSelectedClass] = useState<string>('All');
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');

  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [classes, setClasses] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);
  const [editForm, setEditForm] = useState({
      status: 'Hadir' as AttendanceStatus,
      checkIn: '',
      duha: '',
      zuhur: '',
      ashar: '',
      checkOut: ''
  });

  const isStudent = userRole === UserRole.SISWA;

  // Load Daftar Kelas
  useEffect(() => {
    if (isMockMode) {
        setClasses(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
        return;
    }
    if (db) {
        db.collection('classes').get().then(s => setClasses(s.docs.map(d => d.data().name).sort()));
    }
  }, []);

  // Load Data Siswa & Absensi (Merged Logic)
  useEffect(() => {
    setLoading(true);

    if (isMockMode) {
        setTimeout(() => {
            setAllStudents([
                { id: 's1', namaLengkap: 'ADELIA SRI SUNDARI', tingkatRombel: 'XII IPA 1', nisn: '0086806440', status: 'Aktif', jenisKelamin: 'Perempuan', idUnik: '25002' } as any
            ]);
            setAttendanceRecords([
                { 
                    id: 's1_' + selectedDate, studentId: 's1', studentName: 'ADELIA SRI SUNDARI', 
                    class: 'XII IPA 1', status: 'Hadir', date: selectedDate, 
                    checkIn: '07:15:00', duha: '08:20:00', zuhur: '12:30:00', ashar: null, checkOut: null 
                } as any
            ]);
            setLoading(false);
        }, 500);
        return;
    }

    if (!db) return;

    // Ambil Seluruh Siswa Aktif
    const unsubStudents = db.collection('students').where('status', '==', 'Aktif').onSnapshot(snap => {
        setAllStudents(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student)));
    });

    // Ambil Log Absensi Tanggal Terpilih
    const unsubAttendance = db.collection('attendance').where('date', '==', selectedDate).onSnapshot(snap => {
        setAttendanceRecords(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as AttendanceRecord)));
        setLoading(false);
    }, err => {
        console.error(err);
        setLoading(false);
    });

    return () => { unsubStudents(); unsubAttendance(); };
  }, [selectedDate]);

  // Proses Penggabungan Data (Merging)
  const displayData = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();

    // Filter siswa berdasarkan kelas & pencarian
    const filteredStudents = allStudents.filter(s => {
        const matchesClass = selectedClass === 'All' || s.tingkatRombel === selectedClass;
        const matchesSearch = q === '' || 
                             (s.namaLengkap || '').toLowerCase().includes(q) ||
                             String(s.idUnik || '').toLowerCase().includes(q);
        return matchesClass && matchesSearch;
    }).sort((a, b) => (a.namaLengkap || '').localeCompare(b.namaLengkap || ''));

    const attMap = new Map(attendanceRecords.map(r => [r.studentId, r]));

    return filteredStudents.map(student => {
        const record = attMap.get(student.id!);
        // Jika ada record, gunakan. Jika tidak, buat record virtual "Alpha"
        const finalRecord = record || {
            id: `${student.id}_${selectedDate}`,
            studentId: student.id!,
            studentName: student.namaLengkap,
            class: student.tingkatRombel,
            date: selectedDate,
            status: 'Alpha',
            checkIn: null, duha: null, zuhur: null, ashar: null, checkOut: null,
            idUnik: student.idUnik
        } as any;

        return finalRecord;
    }).filter(r => filterStatus === 'All' || r.status === filterStatus);
  }, [allStudents, attendanceRecords, selectedDate, searchQuery, selectedClass, filterStatus]);

  const cleanTime = (val: string | null) => {
      if (!val) return '';
      return val.substring(0, 5);
  };

  const handleEditClick = (record: AttendanceRecord) => {
      setEditingRecord(record);
      setEditForm({ 
          status: record.status || 'Alpha', 
          checkIn: cleanTime(record.checkIn), 
          duha: cleanTime(record.duha), 
          zuhur: cleanTime(record.zuhur), 
          ashar: cleanTime(record.ashar), 
          checkOut: cleanTime(record.checkOut) 
      });
      setIsEditModalOpen(true);
  };

  const handleResetRecord = async (record: AttendanceRecord) => {
      // Tombol ini hanya bekerja jika log sudah ada di database (bukan status virtual Alpha)
      const isExisting = attendanceRecords.find(r => r.studentId === record.studentId);

      if (!isExisting) {
          toast.error("Siswa ini memang belum melakukan presensi.");
          return;
      }

      if (!window.confirm(`Hapus seluruh log kehadiran ${record.studentName} tanggal ${selectedDate}? Status akan kembali menjadi 'Belum Direkam'.`)) return;

      const toastId = toast.loading("Menghapus data di Firestore...");
      try {
          if (!isMockMode && db) {
              // Menghapus dokumen dari Firestore secara permanen
              await db.collection('attendance').doc(record.id).delete();
          } else if (isMockMode) {
              setAttendanceRecords(prev => prev.filter(r => r.id !== record.id));
          }
          toast.success("Data kehadiran berhasil direset", { id: toastId });
      } catch (e: any) {
          console.error("Delete Error:", e);
          toast.error("Gagal menghapus data: " + e.message, { id: toastId });
      }
  };

  const handleSaveEdit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingRecord) return;

      setSaving(true);
      const toastId = toast.loading("Menyimpan perubahan...");
      try {
          const payload: any = {
              status: editForm.status,
              checkIn: editForm.checkIn ? `${editForm.checkIn}:00` : null,
              duha: editForm.duha ? `${editForm.duha}:00` : null,
              zuhur: editForm.zuhur ? `${editForm.zuhur}:00` : null,
              ashar: editForm.ashar ? `${editForm.ashar}:00` : null,
              checkOut: editForm.checkOut ? `${editForm.checkOut}:00` : null,
              studentId: editingRecord.studentId,
              studentName: editingRecord.studentName,
              class: editingRecord.class,
              date: selectedDate,
              idUnik: (editingRecord as any).idUnik || ''
          };

          if (!isMockMode && db) {
              await db.collection('attendance').doc(editingRecord.id).set(payload, { merge: true });
          } else if (isMockMode) {
              setAttendanceRecords(prev => {
                  const filtered = prev.filter(r => r.studentId !== editingRecord.studentId);
                  return [...filtered, { id: editingRecord.id, ...payload }];
              });
          }

          toast.success("Log diperbarui", { id: toastId });
          setIsEditModalOpen(false);
      } catch (e: any) {
          toast.error("Gagal menyimpan: " + e.message, { id: toastId });
      } finally {
          setSaving(false);
      }
  };

  return (
    <Layout title="Riwayat Absensi" subtitle={isStudent ? "Log Kehadiran Saya" : "Manajemen Data Riwayat"} icon={CalendarIcon} onBack={onBack}>
      <div className="p-4 lg:p-6 pb-32 space-y-6">

        {/* Filters Panel */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm space-y-5">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pilih Tanggal</label>
                    <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-inner" />
                </div>
                {!isStudent && (
                    <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Filter Rombel</label>
                        <div className="relative">
                            <select value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none appearance-none cursor-pointer shadow-inner">
                                <option value="All">SEMUA KELAS</option>
                                {classes.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                    </div>
                )}
            </div>

            <div className="relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input 
                    type="text" 
                    placeholder="Cari Nama atau ID Unik..." 
                    value={searchQuery}
                    onChange={e => setSearchQuery(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 bg-slate-50 dark:bg-slate-900 border border-transparent focus:border-indigo-100 rounded-2xl text-xs font-bold shadow-inner outline-none transition-all"
                />
            </div>

            {!isStudent && (
                <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
                    {['All', 'Hadir', 'Sakit', 'Izin', 'Alpha', 'Haid'].map(s => (
                        <button 
                            key={s} 
                            onClick={() => setFilterStatus(s)} 
                            className={`px-5 py-2.5 rounded-xl text-[9px] font-black uppercase transition-all border whitespace-nowrap ${filterStatus === s ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-500/20' : 'bg-slate-50 dark:bg-slate-900 text-slate-400 border-slate-100 dark:border-slate-800'}`}
                        >
                            {s === 'Alpha' ? 'Belum Direkam' : s}
                        </button>
                    ))}
                </div>
            )}
        </div>

        {/* List Content */}
        <div className="space-y-4">
            {loading ? (
                <div className="py-20 text-center flex flex-col items-center gap-3">
                    <Loader2 className="w-10 h-10 animate-spin text-indigo-500 opacity-20" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sinkronisasi Database...</p>
                </div>
            ) : displayData.length > 0 ? (
                <div className="grid grid-cols-1 gap-4">
                    {displayData.map((r) => {
                        const hasData = attendanceRecords.find(att => att.studentId === r.studentId);
                        return (
                        <div key={r.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col sm:flex-row sm:items-center justify-between group relative overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-500">
                            <div className={`absolute top-0 left-0 w-1.5 h-full ${r.status === 'Haid' ? 'bg-rose-500' : r.status === 'Hadir' ? 'bg-emerald-500' : r.status === 'Alpha' ? 'bg-slate-200' : 'bg-amber-400'}`}></div>

                            <div className="flex items-center gap-4 flex-1 min-w-0 mb-4 sm:mb-0">
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-lg shrink-0 border-2 transition-transform group-hover:scale-105 ${r.status === 'Haid' ? 'bg-rose-50 text-rose-600 border-rose-100' : r.status === 'Alpha' ? 'bg-slate-50 text-slate-400 border-slate-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100'}`}>
                                    {(r.studentName || '?').charAt(0)}
                                </div>
                                <div className="min-w-0">
                                    <h4 className={`font-black text-xs uppercase truncate tracking-tight leading-none mb-2 ${r.status === 'Alpha' ? 'text-slate-400' : 'text-slate-800 dark:text-white'}`}>{r.studentName}</h4>
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase ${r.status === 'Hadir' ? 'bg-emerald-50 text-emerald-600' : r.status === 'Haid' ? 'bg-rose-50 text-rose-600' : r.status === 'Alpha' ? 'bg-slate-100 text-slate-400' : 'bg-amber-50 text-amber-600'}`}>
                                            {r.status === 'Alpha' ? 'BELUM DIREKAM' : r.status}
                                        </span>
                                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{r.class || '-'}</span>
                                    </div>
                                </div>
                            </div>

                            <div className="flex items-center justify-between sm:justify-end gap-6 pl-2 sm:pl-0 border-t sm:border-0 border-slate-50 dark:border-slate-800 pt-4 sm:pt-0">
                                <div className="flex flex-col items-center">
                                    <p className={`text-[12px] font-mono font-black ${r.checkIn ? 'text-slate-800 dark:text-white' : 'text-slate-200'}`}>{cleanTime(r.checkIn) || '--:--'}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Masuk</p>
                                </div>
                                <div className="flex flex-col items-center">
                                    <p className={`text-[12px] font-mono font-black ${r.checkOut ? 'text-slate-800 dark:text-white' : 'text-slate-200'}`}>{cleanTime(r.checkOut) || '--:--'}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Pulang</p>
                                </div>

                                {!isStudent && (
                                    <div className="flex gap-2 ml-4">
                                        <button 
                                            onClick={() => handleEditClick(r)} 
                                            className="p-3 bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-indigo-600 rounded-2xl transition-all shadow-sm active:scale-90"
                                            title="Edit Log"
                                        >
                                            <PencilIcon className="w-4 h-4" />
                                        </button>
                                        <button 
                                            onClick={() => handleResetRecord(r)} 
                                            className={`p-3 rounded-2xl transition-all shadow-sm active:scale-90 ${hasData ? 'bg-rose-50 dark:bg-rose-900/20 text-rose-500 hover:bg-rose-600 hover:text-white' : 'bg-slate-50/50 text-slate-200 cursor-not-allowed'}`}
                                            title="Reset Kehadiran (Hapus Log)"
                                        >
                                            <TrashIcon className="w-4 h-4" />
                                        </button>
                                    </div>
                                )}
                            </div>
                        </div>
                    )})}
                </div>
            ) : (
                <div className="py-24 text-center bg-white dark:bg-[#151E32] rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800 shadow-inner">
                    <Search className="w-12 h-12 text-slate-100 dark:text-slate-800 mx-auto mb-4" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tidak Ada Data Siswa</p>
                </div>
            )}
        </div>
      </div>

      {/* Modal Edit/Koreksi */}
      {isEditModalOpen && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-300">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-sm rounded-[3rem] p-8 shadow-2xl border border-white/10 animate-in zoom-in duration-300 max-h-[90vh] overflow-y-auto scrollbar-hide">
                  <div className="text-center mb-8">
                      <h3 className="font-black text-sm text-slate-800 dark:text-white uppercase tracking-[0.2em]">Koreksi Log</h3>
                      <p className="text-[9px] font-bold text-indigo-500 mt-2 truncate">{(editingRecord?.studentName || '').toUpperCase()}</p>
                  </div>

                  <form onSubmit={handleSaveEdit} className="space-y-6">
                      <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1 tracking-widest">Status Presensi</label>
                        <div className="relative">
                            <select 
                                value={editForm.status} 
                                onChange={(e) => setEditForm({...editForm, status: e.target.value as AttendanceStatus})} 
                                className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none shadow-inner appearance-none cursor-pointer"
                            >
                                <option value="Alpha">BELUM DIREKAM (ALPHA)</option>
                                <option value="Hadir">HADIR</option>
                                <option value="Haid">HAID (Siklus Bulanan)</option>
                                <option value="Sakit">SAKIT</option>
                                <option value="Izin">IZIN / DISPEN</option>
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-1.5">
                              <label className="text-[8px] font-black text-slate-400 uppercase ml-1 tracking-widest">Jam Masuk</label>
                              <input type="time" value={editForm.checkIn} onChange={e => setEditForm({...editForm, checkIn: e.target.value})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black shadow-inner" />
                          </div>
                          <div className="space-y-1.5">
                              <label className="text-[8px] font-black text-slate-400 uppercase ml-1 tracking-widest">Jam Pulang</label>
                              <input type="time" value={editForm.checkOut} onChange={e => setEditForm({...editForm, checkOut: e.target.value})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black shadow-inner" />
                          </div>
                      </div>

                      <div className="space-y-4 pt-2 border-t border-slate-100 dark:border-slate-800">
                          <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest text-center">Log Sesi Ibadah</p>
                          <div className="grid grid-cols-3 gap-2">
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Duha</label>
                                <input type="time" value={editForm.duha} onChange={e => setEditForm({...editForm, duha: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Zuhur</label>
                                <input type="time" value={editForm.zuhur} onChange={e => setEditForm({...editForm, zuhur: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Ashar</label>
                                <input type="time" value={editForm.ashar} onChange={e => setEditForm({...editForm, ashar: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                          </div>
                      </div>

                      <div className="flex flex-col gap-3 pt-6">
                        <button type="submit" disabled={saving} className="w-full py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 active:scale-95 transition-all">
                            {saving ? <Loader2 className="w-4 h-4 animate-spin"/> : <SaveIcon className="w-4 h-4" />} Simpan Perubahan
                        </button>
                        <button type="button" onClick={() => setIsEditModalOpen(false)} className="w-full py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-2xl text-[9px] font-black uppercase tracking-widest active:scale-95 transition-all">Batalkan</button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </Layout>
  );
};

export default AttendanceHistory;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './Layout';
import { db, auth, isMockMode } from '../services/firebase';
import { 
  CalendarIcon, CheckCircleIcon, ClockIcon, Search, 
  PencilIcon, TrashIcon, Loader2, HeartIcon, 
  SaveIcon, ChevronDownIcon, ArrowLeftIcon, BookOpenIcon
} from './Icons';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ViewState, AttendanceStatus, UserRole, AttendanceRecord, Student } from '../types';

interface AttendanceHistoryProps {
  onBack: () => void;
  onNavigate: (view: ViewState) => void;
  userRole: UserRole;
}

const AttendanceHistory: React.FC<AttendanceHistoryProps> = ({ onBack, onNavigate, userRole }) => {
  const [selectedDate, setSelectedDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [selectedClass, setSelectedClass] = useState<string>('All');
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');

  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [classes, setClasses] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);
  const [editForm, setEditForm] = useState({
      status: 'Hadir' as AttendanceStatus,
      checkIn: '',
      duha: '',
      zuhur: '',
      ashar: '',
      checkOut: ''
  });

  const isStudent = userRole === UserRole.SISWA;

  // Load Daftar Kelas
  useEffect(() => {
    if (isMockMode) {
        setClasses(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
        return;
    }
    if (db) {
        db.collection('classes').get().then(s => setClasses(s.docs.map(d => d.data().name).sort()));
    }
  }, []);

  // Load Data Siswa & Absensi (Merged Logic)
  useEffect(() => {
    setLoading(true);

    if (isMockMode) {
        setTimeout(() => {
            setAllStudents([
                { id: 's1', namaLengkap: 'ADELIA SRI SUNDARI', tingkatRombel: 'XII IPA 1', nisn: '0086806440', status: 'Aktif', jenisKelamin: 'Perempuan', idUnik: '25002' } as any
            ]);
            setAttendanceRecords([
                { 
                    id: 's1_' + selectedDate, studentId: 's1', studentName: 'ADELIA SRI SUNDARI', 
                    class: 'XII IPA 1', status: 'Hadir', date: selectedDate, 
                    checkIn: '07:15:00', duha: '08:20:00', zuhur: '12:30:00', ashar: null, checkOut: null 
                } as any
            ]);
            setLoading(false);
        }, 500);
        return;
    }

    if (!db) return;

    // Ambil Seluruh Siswa Aktif
    const unsubStudents = db.collection('students').where('status', '==', 'Aktif').onSnapshot(snap => {
        setAllStudents(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student)));
    });

    // Ambil Log Absensi Tanggal Terpilih
    const unsubAttendance = db.collection('attendance').where('date', '==', selectedDate).onSnapshot(snap => {
        setAttendanceRecords(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as AttendanceRecord)));
        setLoading(false);
    }, err => {
        console.error(err);
        setLoading(false);
    });

    return () => { unsubStudents(); unsubAttendance(); };
  }, [selectedDate]);

  // Proses Penggabungan Data (Merging)
  const displayData = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();

    // Filter siswa berdasarkan kelas & pencarian
    const filteredStudents = allStudents.filter(s => {
        const matchesClass = selectedClass === 'All' || s.tingkatRombel === selectedClass;
        const matchesSearch = q === '' || 
                             (s.namaLengkap || '').toLowerCase().includes(q) ||
                             String(s.idUnik || '').toLowerCase().includes(q);
        return matchesClass && matchesSearch;
    }).sort((a, b) => (a.namaLengkap || '').localeCompare(b.namaLengkap || ''));

    const attMap = new Map(attendanceRecords.map(r => [r.studentId, r]));

    return filteredStudents.map(student => {
        const record = attMap.get(student.id!);
        // Jika ada record, gunakan. Jika tidak, buat record virtual "Alpha"
        const finalRecord = record || {
            id: `${student.id}_${selectedDate}`,
            studentId: student.id!,
            studentName: student.namaLengkap,
            class: student.tingkatRombel,
            date: selectedDate,
            status: 'Alpha',
            checkIn: null, duha: null, zuhur: null, ashar: null, checkOut: null,
            idUnik: student.idUnik
        } as any;

        return finalRecord;
    }).filter(r => filterStatus === 'All' || r.status === filterStatus);
  }, [allStudents, attendanceRecords, selectedDate, searchQuery, selectedClass, filterStatus]);

  const cleanTime = (val: string | null) => {
      if (!val) return '';
      // Menghandle format "HH:mm (Haid)" atau "HH:mm:ss"
      if (val.includes('(')) return val.split(' ')[0];
      return val.substring(0, 5);
  };

  const handleEditClick = (record: AttendanceRecord) => {
      setEditingRecord(record);
      setEditForm({ 
          status: record.status || 'Alpha', 
          checkIn: cleanTime(record.checkIn), 
          duha: cleanTime(record.duha), 
          zuhur: cleanTime(record.zuhur), 
          ashar: cleanTime(record.ashar), 
          checkOut: cleanTime(record.checkOut) 
      });
      setIsEditModalOpen(true);
  };

  const handleResetRecord = async (record: AttendanceRecord) => {
      const isExisting = attendanceRecords.find(r => r.studentId === record.studentId);
      if (!isExisting) {
          toast.error("Siswa ini memang belum melakukan presensi.");
          return;
      }
      if (!window.confirm(`Hapus seluruh log kehadiran ${record.studentName} tanggal ${selectedDate}? Status akan kembali menjadi 'Belum Direkam'.`)) return;
      const toastId = toast.loading("Menghapus data di Firestore...");
      try {
          if (!isMockMode && db) {
              await db.collection('attendance').doc(record.id).delete();
          } else if (isMockMode) {
              setAttendanceRecords(prev => prev.filter(r => r.id !== record.id));
          }
          toast.success("Data kehadiran berhasil direset", { id: toastId });
      } catch (e: any) {
          console.error("Delete Error:", e);
          toast.error("Gagal menghapus data: " + e.message, { id: toastId });
      }
  };

  const handleSaveEdit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingRecord) return;
      setSaving(true);
      const toastId = toast.loading("Menyimpan perubahan...");
      try {
          const payload: any = {
              status: editForm.status,
              checkIn: editForm.checkIn ? (editForm.status === 'Haid' ? `${editForm.checkIn} (Haid)` : `${editForm.checkIn}:00`) : null,
              duha: editForm.duha ? (editForm.status === 'Haid' ? `${editForm.duha} (Haid)` : `${editForm.duha}:00`) : null,
              zuhur: editForm.zuhur ? (editForm.status === 'Haid' ? `${editForm.zuhur} (Haid)` : `${editForm.zuhur}:00`) : null,
              ashar: editForm.ashar ? (editForm.status === 'Haid' ? `${editForm.ashar} (Haid)` : `${editForm.ashar}:00`) : null,
              checkOut: editForm.checkOut ? `${editForm.checkOut}:00` : null,
              studentId: editingRecord.studentId,
              studentName: editingRecord.studentName,
              class: editingRecord.class,
              date: selectedDate,
              idUnik: (editingRecord as any).idUnik || ''
          };
          if (!isMockMode && db) {
              await db.collection('attendance').doc(editingRecord.id).set(payload, { merge: true });
          } else if (isMockMode) {
              setAttendanceRecords(prev => {
                  const filtered = prev.filter(r => r.studentId !== editingRecord.studentId);
                  return [...filtered, { id: editingRecord.id, ...payload }];
              });
          }
          toast.success("Log diperbarui", { id: toastId });
          setIsEditModalOpen(false);
      } catch (e: any) {
          toast.error("Gagal menyimpan: " + e.message, { id: toastId });
      } finally {
          setSaving(false);
      }
  };

  return (
    <Layout title="Riwayat Absensi" subtitle={isStudent ? "Log Kehadiran Saya" : "Manajemen Data Riwayat"} icon={CalendarIcon} onBack={onBack}>
      <div className="p-4 lg:p-6 pb-32 space-y-6">
        {/* Filters Panel */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm space-y-5">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pilih Tanggal</label>
                    <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-inner" />
                </div>
                {!isStudent && (
                    <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Filter Rombel</label>
                        <div className="relative">
                            <select value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none appearance-none cursor-pointer shadow-inner">
                                <option value="All">SEMUA KELAS</option>
                                {classes.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                    </div>
                )}
            </div>
            <div className="relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input type="text" placeholder="Cari Nama atau ID Unik..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 dark:bg-slate-900 border border-transparent focus:border-indigo-100 rounded-2xl text-xs font-bold shadow-inner outline-none transition-all" />
            </div>
            {!isStudent && (
                <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
                    {['All', 'Hadir', 'Sakit', 'Izin', 'Alpha', 'Haid'].map(s => (
                        <button key={s} onClick={() => setFilterStatus(s)} className={`px-5 py-2.5 rounded-xl text-[9px] font-black uppercase transition-all border whitespace-nowrap ${filterStatus === s ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-500/20' : 'bg-slate-50 dark:bg-slate-900 text-slate-400 border-slate-100 dark:border-slate-800'}`}>{s === 'Alpha' ? 'Belum Direkam' : s}</button>
                    ))}
                </div>
            )}
        </div>

        {/* List Content */}
        <div className="space-y-4">
            {loading ? (
                <div className="py-20 text-center flex flex-col items-center gap-3">
                    <Loader2 className="w-10 h-10 animate-spin text-indigo-500 opacity-20" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sinkronisasi Database...</p>
                </div>
            ) : displayData.length > 0 ? (
                <div className="grid grid-cols-1 gap-4">
                    {displayData.map((r) => {
                        const hasData = attendanceRecords.find(att => att.studentId === r.studentId);
                        const haidTime = (r.duha || r.zuhur || r.ashar || '').includes('(Haid)') ? cleanTime(r.duha || r.zuhur || r.ashar) : '';
                        return (
                        <div key={r.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col sm:flex-row sm:items-center justify-between group relative overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-500">
                            <div className={`absolute top-0 left-0 w-1.5 h-full ${r.status === 'Haid' ? 'bg-rose-500' : r.status === 'Hadir' ? 'bg-emerald-500' : r.status === 'Alpha' ? 'bg-slate-200' : 'bg-amber-400'}`}></div>
                            <div className="flex items-center gap-4 flex-1 min-w-0 mb-4 sm:mb-0">
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-lg shrink-0 border-2 transition-transform group-hover:scale-105 ${r.status === 'Haid' ? 'bg-rose-50 text-rose-600 border-rose-100' : r.status === 'Alpha' ? 'bg-slate-50 text-slate-400 border-slate-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100'}`}>{(r.studentName || '?').charAt(0)}</div>
                                <div className="min-w-0">
                                    <h4 className={`font-black text-xs uppercase truncate tracking-tight leading-none mb-2 ${r.status === 'Alpha' ? 'text-slate-400' : 'text-slate-800 dark:text-white'}`}>{r.studentName}</h4>
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase ${r.status === 'Hadir' ? 'bg-emerald-50 text-emerald-600' : r.status === 'Haid' ? 'bg-rose-50 text-rose-600' : r.status === 'Alpha' ? 'bg-slate-100 text-slate-400' : 'bg-amber-50 text-amber-600'}`}>
                                            {r.status === 'Alpha' ? 'BELUM DIREKAM' : r.status === 'Haid' ? `HAID (${haidTime || '--:--'})` : r.status}
                                        </span>
                                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{r.class || '-'}</span>
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center justify-between sm:justify-end gap-6 pl-2 sm:pl-0 border-t sm:border-0 border-slate-50 dark:border-slate-800 pt-4 sm:pt-0">
                                <div className="flex flex-col items-center">
                                    <p className={`text-[12px] font-mono font-black ${r.checkIn ? 'text-slate-800 dark:text-white' : 'text-slate-200'}`}>{cleanTime(r.checkIn) || '--:--'}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Masuk</p>
                                </div>
                                <div className="flex flex-col items-center">
                                    <p className={`text-[12px] font-mono font-black ${r.checkOut ? 'text-slate-800 dark:text-white' : 'text-slate-200'}`}>{cleanTime(r.checkOut) || '--:--'}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Pulang</p>
                                </div>
                                {!isStudent && (
                                    <div className="flex gap-2 ml-4">
                                        <button onClick={() => handleEditClick(r)} className="p-3 bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-indigo-600 rounded-2xl transition-all shadow-sm active:scale-90" title="Edit Log"><PencilIcon className="w-4 h-4" /></button>
                                        <button onClick={() => handleResetRecord(r)} className={`p-3 rounded-2xl transition-all shadow-sm active:scale-90 ${hasData ? 'bg-rose-50 dark:bg-rose-900/20 text-rose-500 hover:bg-rose-600 hover:text-white' : 'bg-slate-50/50 text-slate-200 cursor-not-allowed'}`} title="Reset Kehadiran (Hapus Log)"><TrashIcon className="w-4 h-4" /></button>
                                    </div>
                                )}
                            </div>
                        </div>
                    )})}
                </div>
            ) : (
                <div className="py-24 text-center bg-white dark:bg-[#151E32] rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800 shadow-inner">
                    <Search className="w-12 h-12 text-slate-100 dark:text-slate-800 mx-auto mb-4" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tidak Ada Data Siswa</p>
                </div>
            )}
        </div>
      </div>

      {/* Modal Edit/Koreksi */}
      {isEditModalOpen && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-300">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-sm rounded-[3rem] p-8 shadow-2xl border border-white/10 animate-in zoom-in duration-300 max-h-[90vh] overflow-y-auto scrollbar-hide">
                  <div className="text-center mb-8">
                      <h3 className="font-black text-sm text-slate-800 dark:text-white uppercase tracking-[0.2em]">Koreksi Log</h3>
                      <p className="text-[9px] font-bold text-indigo-500 mt-2 truncate">{(editingRecord?.studentName || '').toUpperCase()}</p>
                  </div>
                  <form onSubmit={handleSaveEdit} className="space-y-6">
                      <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1 tracking-widest">Status Presensi</label>
                        <div className="relative">
                            <select value={editForm.status} onChange={(e) => setEditForm({...editForm, status: e.target.value as AttendanceStatus})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none shadow-inner appearance-none cursor-pointer">
                                <option value="Alpha">BELUM DIREKAM (ALPHA)</option>
                                <option value="Hadir">HADIR</option>
                                <option value="Haid">HAID (Siklus Bulanan)</option>
                                <option value="Sakit">SAKIT</option>
                                <option value="Izin">IZIN / DISPEN</option>
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-1.5">
                              <label className="text-[8px] font-black text-slate-400 uppercase ml-1 tracking-widest">Jam Masuk</label>
                              <input type="time" value={editForm.checkIn} onChange={e => setEditForm({...editForm, checkIn: e.target.value})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black shadow-inner" />
                          </div>
                          <div className="space-y-1.5">
                              <label className="text-[8px] font-black text-slate-400 uppercase ml-1 tracking-widest">Jam Pulang</label>
                              <input type="time" value={editForm.checkOut} onChange={e => setEditForm({...editForm, checkOut: e.target.value})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black shadow-inner" />
                          </div>
                      </div>
                      <div className="space-y-4 pt-2 border-t border-slate-100 dark:border-slate-800">
                          <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest text-center">Log Sesi Ibadah</p>
                          <div className="grid grid-cols-3 gap-2">
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Duha</label>
                                <input type="time" value={editForm.duha} onChange={e => setEditForm({...editForm, duha: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Zuhur</label>
                                <input type="time" value={editForm.zuhur} onChange={e => setEditForm({...editForm, zuhur: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Ashar</label>
                                <input type="time" value={editForm.ashar} onChange={e => setEditForm({...editForm, ashar: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                          </div>
                      </div>
                      <div className="flex flex-col gap-3 pt-6">
                        <button type="submit" disabled={saving} className="w-full py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 active:scale-95 transition-all">{saving ? <Loader2 className="w-4 h-4 animate-spin"/> : <SaveIcon className="w-4 h-4" />} Simpan Perubahan</button>
                        <button type="button" onClick={() => setIsEditModalOpen(false)} className="w-full py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-2xl text-[9px] font-black uppercase tracking-widest active:scale-95 transition-all">Batalkan</button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </Layout>
  );
};

