interface AttendanceHistoryProps {
  onBack: () => void;
  onNavigate: (view: ViewState) => void;
  userRole: UserRole;
}

const AttendanceHistory: React.FC<AttendanceHistoryProps> = ({ onBack, onNavigate, userRole }) => {
  const [selectedDate, setSelectedDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [selectedClass, setSelectedClass] = useState<string>('All');
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');

  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [classes, setClasses] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);
  const [editForm, setEditForm] = useState({
      status: 'Hadir' as AttendanceStatus,
      checkIn: '',
      duha: '',
      zuhur: '',
      ashar: '',
      checkOut: ''
  });

  const isStudent = userRole === UserRole.SISWA;

  // Load Daftar Kelas
  useEffect(() => {
    if (isMockMode) {
        setClasses(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
        return;
    }
    if (db) {
        db.collection('classes').get().then(s => setClasses(s.docs.map(d => d.data().name).sort()));
    }
  }, []);

  // Load Data Siswa & Absensi (Merged Logic)
  useEffect(() => {
    setLoading(true);

    if (isMockMode) {
        setTimeout(() => {
            setAllStudents([
                { id: 's1', namaLengkap: 'ADELIA SRI SUNDARI', tingkatRombel: 'XII IPA 1', nisn: '0086806440', status: 'Aktif', jenisKelamin: 'Perempuan', idUnik: '25002' } as any
            ]);
            setAttendanceRecords([
                { 
                    id: 's1_' + selectedDate, studentId: 's1', studentName: 'ADELIA SRI SUNDARI', 
                    class: 'XII IPA 1', status: 'Hadir', date: selectedDate, 
                    checkIn: '07:15:00', duha: '08:20:00', zuhur: '12:30:00', ashar: null, checkOut: null 
                } as any
            ]);
            setLoading(false);
        }, 500);
        return;
    }

    if (!db) return;

    // Ambil Seluruh Siswa Aktif
    const unsubStudents = db.collection('students').where('status', '==', 'Aktif').onSnapshot(snap => {
        setAllStudents(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student)));
    });

    // Ambil Log Absensi Tanggal Terpilih
    const unsubAttendance = db.collection('attendance').where('date', '==', selectedDate).onSnapshot(snap => {
        setAttendanceRecords(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as AttendanceRecord)));
        setLoading(false);
    }, err => {
        console.error(err);
        setLoading(false);
    });

    return () => { unsubStudents(); unsubAttendance(); };
  }, [selectedDate]);

  // Proses Penggabungan Data (Merging)
  const displayData = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();

    // Filter siswa berdasarkan kelas & pencarian
    const filteredStudents = allStudents.filter(s => {
        const matchesClass = selectedClass === 'All' || s.tingkatRombel === selectedClass;
        const matchesSearch = q === '' || 
                             (s.namaLengkap || '').toLowerCase().includes(q) ||
                             String(s.idUnik || '').toLowerCase().includes(q);
        return matchesClass && matchesSearch;
    }).sort((a, b) => (a.namaLengkap || '').localeCompare(b.namaLengkap || ''));

    const attMap = new Map(attendanceRecords.map(r => [r.studentId, r]));

    return filteredStudents.map(student => {
        const record = attMap.get(student.id!);
        // Jika ada record, gunakan. Jika tidak, buat record virtual "Alpha"
        const finalRecord = record || {
            id: `${student.id}_${selectedDate}`,
            studentId: student.id!,
            studentName: student.namaLengkap,
            class: student.tingkatRombel,
            date: selectedDate,
            status: 'Alpha',
            checkIn: null, duha: null, zuhur: null, ashar: null, checkOut: null,
            idUnik: student.idUnik
        } as any;

        return finalRecord;
    }).filter(r => filterStatus === 'All' || r.status === filterStatus);
  }, [allStudents, attendanceRecords, selectedDate, searchQuery, selectedClass, filterStatus]);

  const cleanTime = (val: string | null) => {
      if (!val) return '';
      // Menghandle format "HH:mm (Haid)" atau "HH:mm:ss"
      if (val.includes('(')) return val.split(' ')[0];
      return val.substring(0, 5);
  };

  const handleEditClick = (record: AttendanceRecord) => {
      setEditingRecord(record);
      setEditForm({ 
          status: record.status || 'Alpha', 
          checkIn: cleanTime(record.checkIn), 
          duha: cleanTime(record.duha), 
          zuhur: cleanTime(record.zuhur), 
          ashar: cleanTime(record.ashar), 
          checkOut: cleanTime(record.checkOut) 
      });
      setIsEditModalOpen(true);
  };

  const handleResetRecord = async (record: AttendanceRecord) => {
      // Tombol ini hanya bekerja jika log sudah ada di database (bukan status virtual Alpha)
      const isExisting = attendanceRecords.find(r => r.studentId === record.studentId);

      if (!isExisting) {
          toast.error("Siswa ini memang belum melakukan presensi.");
          return;
      }

      if (!window.confirm(`Hapus seluruh log kehadiran ${record.studentName} tanggal ${selectedDate}? Status akan kembali menjadi 'Belum Direkam'.`)) return;

      const toastId = toast.loading("Menghapus data di Firestore...");
      try {
          if (!isMockMode && db) {
              // Menghapus dokumen dari Firestore secara permanen
              await db.collection('attendance').doc(record.id).delete();
          } else if (isMockMode) {
              setAttendanceRecords(prev => prev.filter(r => r.id !== record.id));
          }
          toast.success("Data kehadiran berhasil direset", { id: toastId });
      } catch (e: any) {
          console.error("Delete Error:", e);
          toast.error("Gagal menghapus data: " + e.message, { id: toastId });
      }
  };

  const handleSaveEdit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingRecord) return;
      setSaving(true);
      const toastId = toast.loading("Menyimpan perubahan...");
      try {
          const payload: any = {
              status: editForm.status,
              checkIn: editForm.checkIn ? (editForm.status === 'Haid' ? `${editForm.checkIn} (Haid)` : `${editForm.checkIn}:00`) : null,
              duha: editForm.duha ? (editForm.status === 'Haid' ? `${editForm.duha} (Haid)` : `${editForm.duha}:00`) : null,
              zuhur: editForm.zuhur ? (editForm.status === 'Haid' ? `${editForm.zuhur} (Haid)` : `${editForm.zuhur}:00`) : null,
              ashar: editForm.ashar ? (editForm.status === 'Haid' ? `${editForm.ashar} (Haid)` : `${editForm.ashar}:00`) : null,
              checkOut: editForm.checkOut ? `${editForm.checkOut}:00` : null,
              studentId: editingRecord.studentId,
              studentName: editingRecord.studentName,
              class: editingRecord.class,
              date: selectedDate,
              idUnik: (editingRecord as any).idUnik || ''
          };
          if (!isMockMode && db) {
              await db.collection('attendance').doc(editingRecord.id).set(payload, { merge: true });
          } else if (isMockMode) {
              setAttendanceRecords(prev => {
                  const filtered = prev.filter(r => r.studentId !== editingRecord.studentId);
                  return [...filtered, { id: editingRecord.id, ...payload }];
              });
          }
          toast.success("Log diperbarui", { id: toastId });
          setIsEditModalOpen(false);
      } catch (e: any) {
          toast.error("Gagal menyimpan: " + e.message, { id: toastId });
      } finally {
          setSaving(false);
      }
  };

  return (
    <Layout title="Riwayat Absensi" subtitle={isStudent ? "Log Kehadiran Saya" : "Manajemen Data Riwayat"} icon={CalendarIcon} onBack={onBack}>
      <div className="p-4 lg:p-6 pb-32 space-y-6">

        {/* Filters Panel */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm space-y-5">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pilih Tanggal</label>
                    <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-inner" />
                </div>
                {!isStudent && (
                    <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Filter Rombel</label>
                        <div className="relative">
                            <select value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none appearance-none cursor-pointer shadow-inner">
                                <option value="All">SEMUA KELAS</option>
                                {classes.map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                    </div>
                )}
            </div>

            <div className="relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input 
                    type="text" 
                    placeholder="Cari Nama atau ID Unik..." 
                    value={searchQuery}
                    onChange={e => setSearchQuery(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 bg-slate-50 dark:bg-slate-900 border border-transparent focus:border-indigo-100 rounded-2xl text-xs font-bold shadow-inner outline-none transition-all"
                />
            </div>

            {!isStudent && (
                <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
                    {['All', 'Hadir', 'Sakit', 'Izin', 'Alpha', 'Haid'].map(s => (
                        <button 
                            key={s} 
                            onClick={() => setFilterStatus(s)} 
                            className={`px-5 py-2.5 rounded-xl text-[9px] font-black uppercase transition-all border whitespace-nowrap ${filterStatus === s ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-500/20' : 'bg-slate-50 dark:bg-slate-900 text-slate-400 border-slate-100 dark:border-slate-800'}`}
                        >
                            {s === 'Alpha' ? 'Belum Direkam' : s}
                        </button>
                    ))}
                </div>
            )}
        </div>

        {/* List Content */}
        <div className="space-y-4">
            {loading ? (
                <div className="py-20 text-center flex flex-col items-center gap-3">
                    <Loader2 className="w-10 h-10 animate-spin text-indigo-500 opacity-20" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sinkronisasi Database...</p>
                </div>
            ) : displayData.length > 0 ? (
                <div className="grid grid-cols-1 gap-4">
                    {displayData.map((r) => {
                        const hasData = attendanceRecords.find(att => att.studentId === r.studentId);
                        const haidTime = (r.duha || r.zuhur || r.ashar || '').includes('(Haid)') ? cleanTime(r.duha || r.zuhur || r.ashar) : '';
                        return (
                        <div key={r.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col sm:flex-row sm:items-center justify-between group relative overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-500">
                            <div className={`absolute top-0 left-0 w-1.5 h-full ${r.status === 'Haid' ? 'bg-rose-500' : r.status === 'Hadir' ? 'bg-emerald-500' : r.status === 'Alpha' ? 'bg-slate-200' : 'bg-amber-400'}`}></div>

                            <div className="flex items-center gap-4 flex-1 min-w-0 mb-4 sm:mb-0">
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-lg shrink-0 border-2 transition-transform group-hover:scale-105 ${r.status === 'Haid' ? 'bg-rose-50 text-rose-600 border-rose-100' : r.status === 'Alpha' ? 'bg-slate-50 text-slate-400 border-slate-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100'}`}>
                                    {(r.studentName || '?').charAt(0)}
                                </div>
                                <div className="min-w-0">
                                    <h4 className={`font-black text-xs uppercase truncate tracking-tight leading-none mb-2 ${r.status === 'Alpha' ? 'text-slate-400' : 'text-slate-800 dark:text-white'}`}>{r.studentName}</h4>
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase ${r.status === 'Hadir' ? 'bg-emerald-50 text-emerald-600' : r.status === 'Haid' ? 'bg-rose-50 text-rose-600' : r.status === 'Alpha' ? 'bg-slate-100 text-slate-400' : 'bg-amber-50 text-amber-600'}`}>
                                            {r.status === 'Alpha' ? 'BELUM DIREKAM' : r.status === 'Haid' ? `HAID (${haidTime || '--:--'})` : r.status}
                                        </span>
                                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{r.class || '-'}</span>
                                    </div>
                                </div>
                            </div>

                            <div className="flex items-center justify-between sm:justify-end gap-6 pl-2 sm:pl-0 border-t sm:border-0 border-slate-50 dark:border-slate-800 pt-4 sm:pt-0">
                                <div className="flex flex-col items-center">
                                    <p className={`text-[12px] font-mono font-black ${r.checkIn ? 'text-slate-800 dark:text-white' : 'text-slate-200'}`}>{cleanTime(r.checkIn) || '--:--'}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Masuk</p>
                                </div>
                                <div className="flex flex-col items-center">
                                    <p className={`text-[12px] font-mono font-black ${r.checkOut ? 'text-slate-800 dark:text-white' : 'text-slate-200'}`}>{cleanTime(r.checkOut) || '--:--'}</p>
                                    <p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Pulang</p>
                                </div>

                                {!isStudent && (
                                    <div className="flex gap-2 ml-4">
                                        <button 
                                            onClick={() => handleEditClick(r)} 
                                            className="p-3 bg-slate-50 dark:bg-slate-900 text-slate-400 hover:text-indigo-600 rounded-2xl transition-all shadow-sm active:scale-90"
                                            title="Edit Log"
                                        >
                                            <PencilIcon className="w-4 h-4" />
                                        </button>
                                        <button 
                                            onClick={() => handleResetRecord(r)} 
                                            className={`p-3 rounded-2xl transition-all shadow-sm active:scale-90 ${hasData ? 'bg-rose-50 dark:bg-rose-900/20 text-rose-500 hover:bg-rose-600 hover:text-white' : 'bg-slate-50/50 text-slate-200 cursor-not-allowed'}`}
                                            title="Reset Kehadiran (Hapus Log)"
                                        >
                                            <TrashIcon className="w-4 h-4" />
                                        </button>
                                    </div>
                                )}
                            </div>
                        </div>
                    )})}
                </div>
            ) : (
                <div className="py-24 text-center bg-white dark:bg-[#151E32] rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800 shadow-inner">
                    <Search className="w-12 h-12 text-slate-100 dark:text-slate-800 mx-auto mb-4" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tidak Ada Data Siswa</p>
                </div>
            )}
        </div>
      </div>

      {/* Modal Edit/Koreksi */}
      {isEditModalOpen && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-300">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-sm rounded-[3rem] p-8 shadow-2xl border border-white/10 animate-in zoom-in duration-300 max-h-[90vh] overflow-y-auto scrollbar-hide">
                  <div className="text-center mb-8">
                      <h3 className="font-black text-sm text-slate-800 dark:text-white uppercase tracking-[0.2em]">Koreksi Log</h3>
                      <p className="text-[9px] font-bold text-indigo-500 mt-2 truncate">{(editingRecord?.studentName || '').toUpperCase()}</p>
                  </div>

                  <form onSubmit={handleSaveEdit} className="space-y-6">
                      <div className="space-y-1.5">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1 tracking-widest">Status Presensi</label>
                        <div className="relative">
                            <select 
                                value={editForm.status} 
                                onChange={(e) => setEditForm({...editForm, status: e.target.value as AttendanceStatus})} 
                                className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black uppercase outline-none shadow-inner appearance-none cursor-pointer"
                            >
                                <option value="Alpha">BELUM DIREKAM (ALPHA)</option>
                                <option value="Hadir">HADIR</option>
                                <option value="Haid">HAID (Siklus Bulanan)</option>
                                <option value="Sakit">SAKIT</option>
                                <option value="Izin">IZIN / DISPEN</option>
                            </select>
                            <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-1.5">
                              <label className="text-[8px] font-black text-slate-400 uppercase ml-1 tracking-widest">Jam Masuk</label>
                              <input type="time" value={editForm.checkIn} onChange={e => setEditForm({...editForm, checkIn: e.target.value})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black shadow-inner" />
                          </div>
                          <div className="space-y-1.5">
                              <label className="text-[8px] font-black text-slate-400 uppercase ml-1 tracking-widest">Jam Pulang</label>
                              <input type="time" value={editForm.checkOut} onChange={e => setEditForm({...editForm, checkOut: e.target.value})} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black shadow-inner" />
                          </div>
                      </div>

                      <div className="space-y-4 pt-2 border-t border-slate-100 dark:border-slate-800">
                          <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest text-center">Log Sesi Ibadah</p>
                          <div className="grid grid-cols-3 gap-2">
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Duha</label>
                                <input type="time" value={editForm.duha} onChange={e => setEditForm({...editForm, duha: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Zuhur</label>
                                <input type="time" value={editForm.zuhur} onChange={e => setEditForm({...editForm, zuhur: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                              <div className="space-y-1">
                                <label className="text-[7px] font-black text-slate-400 uppercase ml-1">Ashar</label>
                                <input type="time" value={editForm.ashar} onChange={e => setEditForm({...editForm, ashar: e.target.value})} className="w-full px-3 py-3 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-xl text-[10px] font-black" />
                              </div>
                          </div>
                      </div>

                      <div className="flex flex-col gap-3 pt-6">
                        <button type="submit" disabled={saving} className="w-full py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 active:scale-95 transition-all">
                            {saving ? <Loader2 className="w-4 h-4 animate-spin"/> : <SaveIcon className="w-4 h-4" />} Simpan Perubahan
                        </button>
                        <button type="button" onClick={() => setIsEditModalOpen(false)} className="w-full py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-2xl text-[9px] font-black uppercase tracking-widest active:scale-95 transition-all">Batalkan</button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </Layout>
  );
};

export default AttendanceHistory;

