interface AttendanceRecord {
    id?: string;
    studentId: string;
    studentName: string;
    idUnik: string;
    jenisKelamin: string;
    class: string;
    date: string;
    status: string;
    checkIn: string | null;
    duha: string | null;
    zuhur: string | null;
    ashar: string | null;
    checkOut: string | null;
