import React, { useState, useEffect, useMemo } from 'react';
import Layout from './Layout';
import { db, auth, isMockMode } from '../services/firebase';
import { 
  CalendarIcon, CheckCircleIcon, ClockIcon, Search, 
  PencilIcon, TrashIcon, Loader2, HeartIcon, 
  SaveIcon, ChevronDownIcon, ArrowLeftIcon, BookOpenIcon,
  XCircleIcon
} from './Icons';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ViewState, AttendanceStatus, UserRole, AttendanceRecord, Student } from '../types';

interface AttendanceHistoryProps {
  onBack: () => void;
  onNavigate: (view: ViewState) => void;
  userRole: UserRole;
}

const AttendanceHistory: React.FC<AttendanceHistoryProps> = ({ onBack, onNavigate, userRole }) => {
  const [selectedDate, setSelectedDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [selectedClass, setSelectedClass] = useState<string>('All');
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');

  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [classes, setClasses] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);
  const [editForm, setEditForm] = useState({
      status: 'Hadir' as AttendanceStatus,
      checkIn: '',
      duha: '',
      zuhur: '',
      ashar: '',
      checkOut: ''
  });

  const isStudent = userRole === UserRole.SISWA;

  // Load Daftar Kelas
  useEffect(() => {
    if (isMockMode) {
        setClasses(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
        return;
    }
    if (db) {
        db.collection('classes').get().then(s => setClasses(s.docs.map(d => d.data().name).sort()));
    }
  }, []);

  // Load Data Siswa & Absensi
  useEffect(() => {
    setLoading(true);

    if (isMockMode) {
        setTimeout(() => {
            setAllStudents([
                { id: 's1', namaLengkap: 'ADELIA SRI SUNDARI', tingkatRombel: 'XII IPA 1', nisn: '0086806440', status: 'Aktif', jenisKelamin: 'Perempuan', idUnik: '25002' } as any
            ]);
            setAttendanceRecords([
                { 
                    id: 's1_' + selectedDate, studentId: 's1', studentName: 'ADELIA SRI SUNDARI', 
                    class: 'XII IPA 1', status: 'Hadir', date: selectedDate, 
                    checkIn: '07:15:00', duha: '08:20:00', zuhur: '12:30:00', ashar: null, checkOut: null 
                } as any
            ]);
            setLoading(false);
        }, 500);
        return;
    }

    if (!db) return;

    const unsubStudents = db.collection('students').where('status', '==', 'Aktif').onSnapshot(snap => {
        setAllStudents(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student)));
    });

    const unsubAttendance = db.collection('attendance').where('date', '==', selectedDate).onSnapshot(snap => {
        setAttendanceRecords(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as AttendanceRecord)));
        setLoading(false);
    }, err => {
        console.error(err);
        setLoading(false);
    });

    return () => { unsubStudents(); unsubAttendance(); };
  }, [selectedDate]);

  // Ekstraksi jam HH:mm secara ketat
  const cleanTime = (val: string | null) => {
      if (!val) return '';
      const timeStr = String(val);
      if (timeStr.includes('(')) return timeStr.split(' ')[0].substring(0, 5);
      return timeStr.substring(0, 5);
  };

  const isHaidTime = (val: string | null) => !!(val && String(val).includes('(Haid)'));

  const displayData = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    const filteredStudents = allStudents.filter(s => {
        const matchesClass = selectedClass === 'All' || s.tingkatRombel === selectedClass;
        const matchesSearch = q === '' || 
                             (s.namaLengkap || '').toLowerCase().includes(q) ||
                             String(s.idUnik || '').toLowerCase().includes(q);
        return matchesClass && matchesSearch;
    }).sort((a, b) => (a.namaLengkap || '').localeCompare(b.namaLengkap || ''));

    const attMap = new Map(attendanceRecords.map(r => [r.studentId, r]));

    return filteredStudents.map(student => {
        const record = attMap.get(student.id!);
        return record || {
            id: `${student.id}_${selectedDate}`,
            studentId: student.id!,
            studentName: student.namaLengkap,
            class: student.tingkatRombel,
            date: selectedDate,
            status: 'Alpha',
            checkIn: null, duha: null, zuhur: null, ashar: null, checkOut: null,
            idUnik: student.idUnik
        } as any;
    }).filter(r => filterStatus === 'All' || r.status === filterStatus);
  }, [allStudents, attendanceRecords, selectedDate, searchQuery, selectedClass, filterStatus]);

  const handleEditClick = (record: AttendanceRecord) => {
      setEditingRecord(record);
      setEditForm({ 
          status: record.status || 'Alpha', 
          checkIn: cleanTime(record.checkIn), 
          duha: cleanTime(record.duha), 
          zuhur: cleanTime(record.zuhur), 
          ashar: cleanTime(record.ashar), 
          checkOut: cleanTime(record.checkOut) 
      });
      setIsEditModalOpen(true);
  };

  const handleResetFull = async (record: AttendanceRecord) => {
      if (!window.confirm(`Hapus seluruh rekaman kehadiran ${record.studentName}?`)) return;
      const toastId = toast.loading("Menghapus data...");
      try {
          if (!isMockMode && db) {
              await db.collection('attendance').doc(record.id).delete();
          }
          toast.success("Log dihapus", { id: toastId });
      } catch (e) { toast.error("Gagal"); }
  };

  const handleSaveEdit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingRecord) return;
      setSaving(true);
      const toastId = toast.loading("Menyimpan...");
      try {
          const status = editForm.status;
          const payload: any = {
              status: status,
              checkIn: editForm.checkIn ? (status === 'Haid' ? `${editForm.checkIn} (Haid)` : `${editForm.checkIn}:00`) : null,
              duha: editForm.duha ? (status === 'Haid' ? `${editForm.duha} (Haid)` : `${editForm.duha}:00`) : null,
              zuhur: editForm.zuhur ? (status === 'Haid' ? `${editForm.zuhur} (Haid)` : `${editForm.zuhur}:00`) : null,
              ashar: editForm.ashar ? (status === 'Haid' ? `${editForm.ashar} (Haid)` : `${editForm.ashar}:00`) : null,
              checkOut: editForm.checkOut ? `${editForm.checkOut}:00` : null,
              studentId: editingRecord.studentId,
              studentName: editingRecord.studentName,
              class: editingRecord.class,
              date: selectedDate,
              idUnik: (editingRecord as any).idUnik || ''
          };
          if (!isMockMode && db) {
              await db.collection('attendance').doc(editingRecord.id).set(payload, { merge: true });
          }
          toast.success("Berhasil", { id: toastId });
          setIsEditModalOpen(false);
      } catch (e) { toast.error("Gagal"); } finally { setSaving(false); }
  };

  const SessionIndicator = ({ label, time }: { label: string, time: string | null }) => {
      const isFilled = !!time;
      const isHaid = isHaidTime(time);
      return (
          <div className={`flex flex-col items-center flex-1 p-2 rounded-xl border transition-all ${
              isFilled ? (isHaid ? 'bg-rose-50 border-rose-100 text-rose-600' : 'bg-emerald-50 border-emerald-100 text-emerald-600') : 'bg-slate-50 dark:bg-slate-900 border-transparent opacity-30'
          }`}>
              <span className="text-[7px] font-black uppercase leading-none mb-1">{label}</span>
              <span className="text-[10px] font-mono font-black">{isFilled ? cleanTime(time) : '--'}</span>
          </div>
      );
  };

  return (
    <Layout title="Riwayat Absensi" subtitle="Database Kehadiran" icon={CalendarIcon} onBack={onBack}>
      <div className="p-4 lg:p-6 pb-32 space-y-6">
        {/* Filters */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black outline-none" />
                {!isStudent && (
                    <select value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl text-[11px] font-black outline-none uppercase">
                        <option value="All">SEMUA KELAS</option>
                        {classes.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                )}
            </div>
            <div className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                <input type="text" placeholder="Cari Nama / ID Unik..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 dark:bg-slate-900 border border-transparent rounded-2xl text-xs font-bold shadow-inner" />
            </div>
        </div>

        {/* List */}
        <div className="space-y-4">
            {loading ? (
                <div className="py-20 text-center"><Loader2 className="w-10 h-10 animate-spin text-indigo-500 mx-auto opacity-20" /></div>
            ) : displayData.length > 0 ? (
                displayData.map((r) => (
                    <div key={r.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm group">
                        <div className="flex items-start justify-between mb-5">
                            <div className="flex items-center gap-4 min-w-0">
                                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black border ${r.status === 'Haid' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100'}`}>{(r.studentName || '?').charAt(0)}</div>
                                <div className="min-w-0">
                                    <h4 className="font-black text-slate-800 dark:text-white text-xs uppercase truncate">{r.studentName}</h4>
                                    <div className="flex items-center gap-2 mt-1">
                                        <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase ${r.status === 'Haid' ? 'bg-rose-50 text-rose-600' : 'bg-indigo-50 text-indigo-600'}`}>{r.status}</span>
                                        <span className="text-[9px] font-black text-slate-300 uppercase">{r.class}</span>
                                    </div>
                                </div>
                            </div>
                            {!isStudent && (
                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                                    <button onClick={() => handleEditClick(r)} className="p-2.5 rounded-xl bg-slate-50 text-slate-400 hover:text-indigo-600"><PencilIcon className="w-4 h-4" /></button>
                                    <button onClick={() => handleResetFull(r)} className="p-2.5 rounded-xl bg-slate-50 text-slate-400 hover:text-rose-600"><TrashIcon className="w-4 h-4" /></button>
                                </div>
                            )}
                        </div>
                        <div className="flex gap-2">
                            <SessionIndicator label="MSK" time={r.checkIn} />
                            <SessionIndicator label="DHA" time={r.duha} />
                            <SessionIndicator label="ZHR" time={r.zuhur} />
                            <SessionIndicator label="ASR" time={r.ashar} />
                            <SessionIndicator label="PLG" time={r.checkOut} />
                        </div>
                    </div>
                ))
            ) : (
                <div className="py-20 text-center text-slate-400 text-[10px] font-black uppercase tracking-widest border-2 border-dashed rounded-[3rem]">Data Tidak Ditemukan</div>
            )}
        </div>
      </div>

      {/* Edit Modal */}
      {isEditModalOpen && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-sm rounded-[3rem] p-8 shadow-2xl animate-in zoom-in duration-300 border border-white/10 max-h-[90vh] overflow-y-auto scrollbar-hide">
                  <h3 className="font-black text-slate-800 dark:text-white uppercase mb-6 text-center tracking-widest text-sm">Koreksi Log Sesi</h3>
                  <form onSubmit={handleSaveEdit} className="space-y-6">
                      <select value={editForm.status} onChange={e => setEditForm({...editForm, status: e.target.value as any})} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border rounded-2xl text-xs font-black uppercase">
                          <option value="Hadir">HADIR</option>
                          <option value="Haid">HAID</option>
                          <option value="Sakit">SAKIT</option>
                          <option value="Izin">IZIN</option>
                          <option value="Alpha">ALPHA</option>
                      </select>
                      <div className="space-y-4">
                          {['checkIn', 'duha', 'zuhur', 'ashar', 'checkOut'].map(f => (
                              <div key={f} className="flex items-center gap-3">
                                  <label className="w-12 text-[8px] font-black text-slate-400 uppercase">{f === 'checkIn' ? 'Msk' : f === 'checkOut' ? 'Plg' : f}</label>
                                  <div className="flex-1 relative">
                                      <input type="time" value={(editForm as any)[f]} onChange={e => setEditForm({...editForm, [f]: e.target.value})} className="w-full p-3 bg-slate-50 dark:bg-slate-900 border rounded-xl text-xs font-black outline-none" />
                                      {(editForm as any)[f] && (
                                          <button type="button" onClick={() => setEditForm({...editForm, [f]: ''})} className="absolute right-3 top-1/2 -translate-y-1/2 text-rose-500"><XCircleIcon className="w-4 h-4"/></button>
                                      )}
                                  </div>
                              </div>
                          ))}
                      </div>
                      <div className="flex flex-col gap-2 pt-4">
                          <button type="submit" disabled={saving} className="w-full py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95">{saving ? 'Menyimpan...' : 'Simpan Koreksi'}</button>
                          <button type="button" onClick={() => setIsEditModalOpen(false)} className="w-full py-4 bg-slate-100 text-slate-500 rounded-2xl text-[10px] font-black uppercase tracking-widest">Batal</button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </Layout>
  );
};

