  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  // DAFTAR KELAS TERPUSAT
  const [classList, setClassList] = useState<string[]>([]);

  const initialFormState: Partial<Student> = {
    namaLengkap: '', nisn: '', idUnik: '', nik: '', email: '',
    tingkatRombel: '', status: 'Aktif', jenisKelamin: 'Laki-laki',
    noTelepon: '', alamat: '', namaAyahKandung: '', namaIbuKandung: '', namaWali: ''
  };

  const [formData, setFormData] = useState<Partial<Student>>(initialFormState);

  // Load class list from 'classes' collection
  useEffect(() => {
    if (isMockMode) {
      setClassList(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
      return;
    }
    if (db) {
      db.collection('classes').get().then(snap => {
        const names = snap.docs.map(d => String(d.data().name).toUpperCase()).sort();
        setClassList(Array.from(new Set(names))); // Ensure uniqueness
      });
    }
  }, []);

  useEffect(() => {
    setLoading(true);
    if (isMockMode) {
        setTimeout(() => {
            setStudents([
                { id: 'm1', namaLengkap: 'ADELIA SRI SUNDARI', nisn: '0086806440', idUnik: '25002', tingkatRombel: 'XII IPA 1', status: 'Aktif', jenisKelamin: 'Perempuan' } as Student,
            ]);
            setLoading(false);
        }, 1000);
        return;
    }
    if (!db) return;

    const unsubscribe = db.collection('students')
        .orderBy('namaLengkap')
        .onSnapshot(snapshot => {
            setStudents(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student)));
            setLoading(false);
        }, () => setLoading(false));
    return () => unsubscribe();
  }, []);

  const processedStudents = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    if (!q) return [...students].sort((a,b) => (a.namaLengkap||'').localeCompare(b.namaLengkap||''));
    return students.filter(s => 
        String(s.namaLengkap || '').toLowerCase().includes(q) || 
        String(s.nisn || '').toLowerCase().includes(q) ||
        String(s.idUnik || '').toLowerCase().includes(q)
    ).sort((a,b) => (a.namaLengkap||'').localeCompare(b.namaLengkap||''));
  }, [students, searchQuery]);

  const handleSave = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!formData.namaLengkap || !formData.nisn || !formData.tingkatRombel) {
          toast.error("Nama, NISN, dan Rombel wajib diisi.");
          return;
      }
      setSaving(true);
      const toastId = toast.loading("Menyimpan...");
      try {
          if (editingId) await updateStudent(editingId, formData);
          else await addStudent(formData as Student);
          setIsModalOpen(false);
          toast.success("Berhasil", { id: toastId });
      } catch (e) { toast.error("Gagal"); } finally { setSaving(false); }
  };

  const canManage = userRole === UserRole.ADMIN || userRole === UserRole.DEVELOPER;

  return (
    <Layout title="Data Induk Siswa" subtitle="Database Master" icon={UsersGroupIcon} onBack={onBack}>
      <div className="p-4 lg:p-8 pb-32 space-y-6">

        {/* Search Header */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col sm:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <input 
                    type="text" 
                    placeholder="Cari Nama, NISN, atau ID Unik..." 
                    value={searchQuery} 
                    onChange={e => setSearchQuery(e.target.value)} 
                    className="w-full bg-slate-50 dark:bg-slate-900 border border-transparent rounded-2xl py-4 pl-12 pr-4 text-xs font-bold outline-none" 
                />
            </div>
            {canManage && (
                <button onClick={() => { setEditingId(null); setFormData(initialFormState); setIsModalOpen(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase shadow-lg active:scale-95 transition-all">
                    <PlusIcon className="w-4 h-4 mr-2 inline" /> Tambah Siswa
                </button>
            )}
        </div>

        {/* List Content */}
        {loading ? (
            <div className="text-center py-20"><Loader2 className="w-10 h-10 animate-spin mx-auto opacity-20" /></div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in duration-500">
                {processedStudents.map(s => (
                    <div key={s.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.2rem] border border-slate-100 dark:border-slate-800 shadow-sm group hover:border-indigo-100 transition-all">
                        <div className="flex items-center gap-4">
                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black border shrink-0 ${s.jenisKelamin === 'Perempuan' ? 'bg-rose-50 text-rose-600' : 'bg-blue-50 text-blue-600'}`}>{(s.namaLengkap || '?').charAt(0)}</div>
                            <div className="min-w-0 flex-1">
                                <h4 className="font-black text-slate-800 dark:text-white text-[11px] uppercase truncate">{s.namaLengkap}</h4>
                                <div className="flex items-center gap-2 mt-1">
                                    <span className="bg-indigo-50 text-indigo-600 px-1.5 py-0.5 rounded text-[8px] font-black uppercase">{s.tingkatRombel}</span>
                                    <span className="text-[9px] font-mono font-bold text-slate-400">{s.idUnik || s.nisn}</span>
                                </div>
                            </div>
                            {canManage && (
                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                                    <button onClick={() => { setEditingId(s.id!); setFormData({...s}); setIsModalOpen(true); }} className="p-2 text-slate-400 hover:text-indigo-600"><PencilIcon className="w-4 h-4" /></button>
                                </div>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        )}
      </div>

      {/* FORM MODAL */}
      {isModalOpen && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-2xl rounded-[2.5rem] shadow-2xl flex flex-col max-h-[90vh] border border-white/10 animate-in zoom-in duration-200">
                  <div className="p-6 border-b flex justify-between items-center">
                      <div>
                          <h3 className="text-lg font-black uppercase tracking-tight">{editingId ? 'Edit Siswa' : 'Tambah Siswa'}</h3>
                          <p className="text-[9px] font-bold text-indigo-500 uppercase mt-1">Integrasi Data Rombel Tunggal</p>
                      </div>
                      <button onClick={() => setIsModalOpen(false)} className="text-slate-400"><XCircleIcon className="w-8 h-8" /></button>
                  </div>

                  <div className="p-8 overflow-y-auto custom-scrollbar flex-1 space-y-6">
                      <form id="studentForm" onSubmit={handleSave} className="space-y-6">
                          <div className="space-y-4">
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Lengkap & Identitas</label>
                              <input required type="text" placeholder="NAMA LENGKAP" value={formData.namaLengkap} onChange={e => setFormData({...formData, namaLengkap: e.target.value.toUpperCase()})} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border rounded-2xl text-xs font-bold" />
                              <div className="grid grid-cols-2 gap-4">
                                  <input required type="text" placeholder="NISN" value={formData.nisn} onChange={e => setFormData({...formData, nisn: e.target.value})} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border rounded-2xl text-xs font-bold" />
                                  <input type="text" placeholder="ID UNIK LOKAL" value={formData.idUnik} onChange={e => setFormData({...formData, idUnik: e.target.value})} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border rounded-2xl text-xs font-bold" />
                              </div>
                          </div>

                          <div className="space-y-4">
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Penempatan Kelas (Rombel)</label>
                              <div className="relative">
                                  <select 
                                    required value={formData.tingkatRombel} 
                                    onChange={e => setFormData({...formData, tingkatRombel: e.target.value})} 
                                    className="w-full p-4 bg-slate-50 dark:bg-slate-900 border rounded-2xl text-xs font-black uppercase appearance-none cursor-pointer"
                                  >
                                      <option value="">-- PILIH ROMBEL RESMI --</option>
                                      {classList.map(c => <option key={c} value={c}>{c}</option>)}
                                  </select>
                                  <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 pointer-events-none" />
                              </div>
                              <p className="text-[8px] text-slate-400 italic">Siswa hanya dapat terdaftar pada satu rombel resmi yang ada di daftar kelas.</p>
                          </div>

                          <div className="grid grid-cols-2 gap-4">
                              <div className="space-y-2">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Gender</label>
                                  <select value={formData.jenisKelamin} onChange={e => setFormData({...formData, jenisKelamin: e.target.value as any})} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border rounded-2xl text-xs font-bold">
                                      <option value="Laki-laki">Laki-laki</option>
                                      <option value="Perempuan">Perempuan</option>
                                  </select>
                              </div>
                              <div className="space-y-2">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">WhatsApp</label>
                                  <input type="text" placeholder="08..." value={formData.noTelepon} onChange={e => setFormData({...formData, noTelepon: e.target.value})} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border rounded-2xl text-xs font-bold" />
                              </div>
                          </div>
                      </form>
                  </div>

                  <div className="p-6 border-t flex gap-3">
                      <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black text-[10px] uppercase tracking-widest">Batal</button>
                      <button type="submit" form="studentForm" disabled={saving} className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
                          {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <SaveIcon className="w-4 h-4" />} Simpan Data Master
                      </button>
                  </div>
              </div>
          </div>
      )}
    </Layout>
  );
};

export default StudentData;

