  const [classes, setClasses] = useState<ClassData[]>([]);
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [academicYears, setAcademicYears] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [importingData, setImportingData] = useState(false);

  const subjectFileInputRef = useRef<HTMLInputElement>(null);
  const studentImportInputRef = useRef<HTMLInputElement>(null);

  // Modals
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [classToDelete, setClassToDelete] = useState<ClassData | null>(null);
  const [newClassData, setNewClassData] = useState({ name: '', level: '10', teacherId: '', academicYear: '' });

  const [isStudentEditModalOpen, setIsStudentEditModalOpen] = useState(false);
  const [editingStudent, setEditingStudent] = useState<Partial<Student> | null>(null);
  const [editDetail, setEditDetail] = useState<Partial<ClassData>>({});

  const canManage = userRole === UserRole.ADMIN || userRole === UserRole.DEVELOPER;

  useEffect(() => {
    setLoading(true);
    if (isMockMode) {
        setClasses([
            { id: '1', name: 'X IPA 1', level: '10', teacherId: 't1', teacherName: 'Budi Santoso, S.Pd', academicYear: '2023/2024' },
            { id: '2', name: 'XI IPS 2', level: '11', teacherId: 't2', teacherName: 'Siti Aminah, M.Ag', academicYear: '2023/2024' }
        ]);
        setAllStudents([
            { id: 's1', namaLengkap: 'ADELIA SRI SUNDARI', idUnik: '25002', tingkatRombel: 'X IPA 1', status: 'Aktif', jenisKelamin: 'Perempuan', nisn: '0086806440' } as Student,
            { id: 's2', namaLengkap: 'ADELIA SRI SUNDARI (DUPLIKAT)', idUnik: '25002', tingkatRombel: 'XI IPS 2', status: 'Aktif', jenisKelamin: 'Perempuan', nisn: '0086806440' } as Student
        ]);
        setLoading(false);
        return;
    }

    if (!db) return;
    const unsubClasses = db.collection('classes').onSnapshot(snap => setClasses(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as ClassData))));
    const unsubStudents = db.collection('students').onSnapshot(snap => setAllStudents(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student))));
    const unsubTeachers = db.collection('teachers').onSnapshot(snap => setTeachers(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Teacher))));
    const unsubYears = db.collection('academic_years').onSnapshot(snap => setAcademicYears(snap.docs.map(d => d.data())));

    setLoading(false);
    return () => { unsubClasses(); unsubStudents(); unsubTeachers(); unsubYears(); };
  }, []);

  // SCANNING DATABASE BERDASARKAN ID UNIK (DETEKSI GANDA)
  const duplicateRegistry = useMemo(() => {
    const counts: Record<string, number> = {};
    allStudents.forEach(s => {
        if (s.idUnik) counts[s.idUnik] = (counts[s.idUnik] || 0) + 1;
    });
    return counts;
  }, [allStudents]);

  const handleKickFromClass = async (student: Student) => {
    if (!student.id) return;
    if (window.confirm(`Keluarkan ${student.namaLengkap} dari kelas ini? Data profil tetap aman di database (Status: Tanpa Kelas).`)) {
        const toastId = toast.loading("Memproses...");
        try {
            if (isMockMode) {
                setAllStudents(prev => prev.map(s => s.id === student.id ? { ...s, tingkatRombel: '' } : s));
            } else {
                await updateStudent(student.id, { tingkatRombel: '' });
            }
            toast.success("Siswa berhasil dikeluarkan dari rombel.", { id: toastId });
        } catch (e) { toast.error("Gagal."); }
    }
  };

  const handleDeleteStudent = async (student: Student) => {
      if (!student.id) return;
      if (window.confirm(`Hapus PERMANEN profil ${student.namaLengkap}? Gunakan ini jika data benar-benar duplikat/salah input.`)) {
          const toastId = toast.loading("Menghapus data induk...");
          try {
              if (isMockMode) setAllStudents(prev => prev.filter(s => s.id !== student.id));
              else await deleteStudent(student.id);
              toast.success("Data dihapus permanen.", { id: toastId });
          } catch (e) { toast.error("Gagal."); }
