              <div>
                  <h2 className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tight">{view === 'detail' ? selectedClass?.name : 'Data Unit Kelas'}</h2>
                  <p className="text-[8px] font-black text-indigo-600 uppercase tracking-widest mt-1">SINKRONISASI DATABASE</p>
              </div>
          </div>
