      <div className="flex-1 overflow-y-auto custom-scrollbar p-5 lg:p-8 pb-40">
          {loading ? (
              <div className="py-20 text-center"><Loader2 className="w-10 h-10 animate-spin text-indigo-500 mx-auto" /></div>
          ) : view === 'list' ? (
