                                  <div className="w-8 h-8 rounded-lg bg-slate-50 dark:bg-slate-900 flex items-center justify-center"><BriefcaseIcon className="w-4 h-4 text-slate-300" /></div>
                                  <div className="min-w-0 flex-1"><p className="text-[7px] font-black text-slate-400 uppercase tracking-tighter">Wali Kelas</p><p className="text-[9px] font-bold text-slate-700 dark:text-slate-400 truncate">{cls.teacherName || 'BELUM DISET'}</p></div>
                              </div>
