import React, { useState, useMemo, useEffect, useRef } from 'react';
import { db, auth, isMockMode } from '../services/firebase';
import { Student, UserRole, Teacher, ClassData } from '../types';
import { 
    BuildingLibraryIcon, UserIcon, ArrowPathIcon, Loader2, ChevronDownIcon,
    PlusIcon, PencilIcon, TrashIcon, BookOpenIcon,
    StarIcon, SaveIcon, ArrowLeftIcon, ArrowRightIcon, BriefcaseIcon, 
    CheckCircleIcon, UsersIcon, Search, XCircleIcon,
    SparklesIcon, IdentificationIcon, ChartBarIcon, CalendarIcon,
    FileSpreadsheet, ShieldCheckIcon, ArrowDownTrayIcon, HeartIcon
} from './Icons';
import { toast } from 'sonner';
import * as XLSX from 'xlsx';
import { format } from 'date-fns';
import { updateClassSubjects } from '../services/classService';
import { bulkImportStudents, updateStudent, deleteStudent } from '../services/studentService';

const ClassList: React.FC<{ onBack: () => void, userRole: UserRole }> = ({ onBack, userRole }) => {
  const [view, setView] = useState<'list' | 'detail'>('list');
  const [selectedClass, setSelectedClass] = useState<ClassData | null>(null);
  const [activeTab, setActiveTab] = useState<'personalia' | 'students' | 'subjects'>('personalia');

  const [classes, setClasses] = useState<ClassData[]>([]);
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [academicYears, setAcademicYears] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const studentImportInputRef = useRef<HTMLInputElement>(null);
  const [isStudentEditModalOpen, setIsStudentEditModalOpen] = useState(false);
  const [editingStudent, setEditingStudent] = useState<Partial<Student> | null>(null);
  const [editDetail, setEditDetail] = useState<Partial<ClassData>>({});

  const canManage = userRole === UserRole.ADMIN || userRole === UserRole.DEVELOPER;

  useEffect(() => {
    setLoading(true);
    if (isMockMode) {
        setClasses([
            { id: '1', name: 'X IPA 1', level: '10', teacherId: 't1', teacherName: 'Budi Santoso, S.Pd', academicYear: '2023/2024' },
            { id: '2', name: 'XI IPS 2', level: '11', teacherId: 't2', teacherName: 'Siti Aminah, M.Ag', academicYear: '2023/2024' }
        ]);
        setAllStudents([
            { id: 'doc_1', namaLengkap: 'ADELIA SRI SUNDARI', idUnik: '25002', tingkatRombel: 'X IPA 1', status: 'Aktif', jenisKelamin: 'Perempuan', nisn: '0086806440' } as Student,
            { id: 'doc_2', namaLengkap: 'ADELIA SRI SUNDARI', idUnik: '25002', tingkatRombel: 'XI IPS 2', status: 'Aktif', jenisKelamin: 'Perempuan', nisn: '0086806440' } as Student
        ]);
        setLoading(false);
        return;
    }

    if (!db) return;
    const unsubClasses = db.collection('classes').onSnapshot(snap => setClasses(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as ClassData))));
    const unsubStudents = db.collection('students').onSnapshot(snap => setAllStudents(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student))));
    const unsubTeachers = db.collection('teachers').onSnapshot(snap => setTeachers(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Teacher))));
    const unsubYears = db.collection('academic_years').onSnapshot(snap => setAcademicYears(snap.docs.map(d => d.data())));

    setLoading(false);
    return () => { unsubClasses(); unsubStudents(); unsubTeachers(); unsubYears(); };
  }, []);

  // PEMINDAIAN DATABASE GLOBAL BERDASARKAN ID UNIK (TRACEABILITY)
  const duplicateMap = useMemo(() => {
    const map: Record<string, string[]> = {};
    allStudents.forEach(s => {
        if (s.idUnik) {
            if (!map[s.idUnik]) map[s.idUnik] = [];
            if (s.tingkatRombel) map[s.idUnik].push(s.tingkatRombel);
        }
    });
    return map;
  }, [allStudents]);

  // AKSI 1: KELUARKAN DARI ROMBEL (Hanya reset kelas pada Dokumen ID ini)
  const handleKickFromClass = async (student: Student) => {
    // PROTEKSI: Pastikan ID Dokumen ada
    if (!student.id) {
        toast.error("Gagal: ID Dokumen tidak ditemukan.");
        return;
    }

    const confirmMsg = `Keluarkan ${student.namaLengkap} dari kelas ${student.tingkatRombel}? 

Tindakan ini hanya akan menghapus status kelas pada baris data ini. Jika ada data ganda di kelas lain, data tersebut tidak akan terpengaruh.`;

    if (window.confirm(confirmMsg)) {
        const toastId = toast.loading("Memproses pengeluaran siswa...");
        try {
            if (isMockMode) {
                setAllStudents(prev => prev.map(s => s.id === student.id ? { ...s, tingkatRombel: '' } : s));
            } else {
                // Langsung update ke Firestore menggunakan ID dokumen yang spesifik
                await db!.collection('students').doc(student.id).update({
                    tingkatRombel: '',
                    lastModified: format(new Date(), 'yyyy-MM-dd HH:mm:ss')
                });
            }
            toast.success("Siswa berhasil dikeluarkan dari rombel.", { id: toastId });
        } catch (e: any) { 
            console.error("Kick Error:", e);
            toast.error("Gagal: " + (e.message || "Bentrokan izin database"), { id: toastId }); 
        }
    }
  };

  // AKSI 2: HAPUS PERMANEN (Membersihkan duplikat murni)
  const handleDeleteStudentPermanently = async (student: Student) => {
    if (!student.id) return;
    const isDuplicate = student.idUnik && (duplicateMap[student.idUnik]?.length || 0) > 1;

    const confirmMsg = isDuplicate 
        ? `PERINGATAN DATA GANDA: Hapus PERMANEN baris data ini dari database? 

Gunakan ini jika Anda ingin membuang salah satu dari dua data yang sama.` 
        : `Hapus PERMANEN profil ${student.namaLengkap} dari sistem?`;

    if (window.confirm(confirmMsg)) {
        const toastId = toast.loading("Menghapus dokumen...");
        try {
            if (isMockMode) {
                setAllStudents(prev => prev.filter(s => s.id !== student.id));
            } else {
                await deleteStudent(student.id);
            }
            toast.success("Dokumen dihapus selamanya.", { id: toastId });
        } catch (e: any) { 
            toast.error("Gagal: " + e.message, { id: toastId }); 
        }
    }
  };

  const handleUpdateClass = async () => {
    if (!selectedClass?.id) return;
    setSaving(true);
    try {
        const teacher = teachers.find(t => t.id === editDetail.teacherId);
        const payload = { teacherId: editDetail.teacherId || '', teacherName: teacher?.name || '', academicYear: editDetail.academicYear || '' };
        if (!isMockMode && db) await db.collection('classes').doc(selectedClass.id).update(payload);
        setSelectedClass(prev => prev ? { ...prev, ...payload } : null);
        toast.success("Informasi wali rombel diperbarui.");
    } catch (e) { toast.error("Gagal menyimpan."); } finally { setSaving(false); }
  };

  const selectedClassStudents = useMemo(() => {
    if (!selectedClass) return [];
    return allStudents.filter(s => s.tingkatRombel === selectedClass.name)
        .sort((a, b) => (a.namaLengkap || '').localeCompare(b.namaLengkap || ''));
