                          <div><label className="text-[9px] font-black text-slate-400 uppercase ml-1">NISN</label><input type="text" value={editingStudent.nisn} onChange={e => setEditingStudent({...editingStudent, nisn: e.target.value})} className="w-full p-4 bg-slate-50 dark:bg-slate-900 border border-slate-200 rounded-2xl text-xs font-bold" /></div>
                      </div>

                      {/* AREA EKSTRA: KELUARKAN SISWA */}
                      <div className="pt-4 border-t border-slate-100 dark:border-slate-800">
                          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3">Tindakan Khusus Rombel</p>
                          <button 
                            type="button"
                            onClick={() => handleKickFromClass(editingStudent.id!, editingStudent.namaLengkap!, editingStudent.tingkatRombel!)}
                            className="w-full flex items-center justify-between p-4 bg-rose-50 dark:bg-rose-950/20 border border-rose-100 dark:border-rose-900/50 rounded-2xl text-rose-600 dark:text-rose-400 group hover:bg-rose-600 hover:text-white transition-all"
                          >
                              <div className="flex items-center gap-3">
                                  <div className="w-8 h-8 rounded-lg bg-white dark:bg-slate-800 flex items-center justify-center shadow-sm group-hover:bg-rose-500"><XCircleIcon className="w-5 h-5" /></div>
                                  <span className="text-[11px] font-black uppercase">Keluarkan Dari {editingStudent.tingkatRombel}</span>
                              </div>
                              <ArrowRightIcon className="w-4 h-4" />
                          </button>
                          <p className="text-[8px] text-slate-400 mt-2 italic px-2">Gunakan tombol di atas jika siswa ini seharusnya tidak berada di kelas {editingStudent.tingkatRombel}.</p>
                      </div>
                  </div>

                  <div className="mt-8 flex gap-3">
                      <button onClick={() => setIsStudentEditModalOpen(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-black text-[9px] uppercase tracking-widest">Tutup</button>
                      <button onClick={handleUpdateStudent} disabled={saving} className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl font-black text-[9px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2 active:scale-95 transition-all"><SaveIcon className="w-4 h-4" /> Simpan Perubahan</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

