import { db, isMockMode } from './firebase';
import { Student } from '../types';

const COLLECTION_NAME = 'students';

export const getStudents = async (): Promise<Student[]> => {
  if (isMockMode) return [];
  try {
    if (!db) throw new Error("Database not initialized");
    const snapshot = await db.collection(COLLECTION_NAME).orderBy('namaLengkap').get();
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
  } catch (error: any) {
    console.error("Error fetching students:", error);
    throw error;
  }
};

/**
 * Mencegah Ganda: Menggunakan NISN sebagai Document ID.
 * Jika NISN sudah ada, Firestore akan melakukan update, bukan insert baru.
 */
export const addStudent = async (student: Student): Promise<void> => {
  if (isMockMode) return;
  try {
    if (!db) throw new Error("Database not initialized");

    // VALIDASI KRITIS: Gunakan NISN sebagai ID Dokumen agar tidak ganda
    const docId = student.nisn ? student.nisn.trim() : db.collection(COLLECTION_NAME).doc().id;

    await db.collection(COLLECTION_NAME).doc(docId).set({
        ...student,
        idUnik: student.idUnik || student.nisn || docId,
        createdAt: student.createdAt || new Date().toISOString(),
        lastModified: new Date().toISOString()
    }, { merge: true });
  } catch (error) {
    console.error("Error adding student:", error);
    throw error;
  }
};

export const updateStudent = async (id: string, student: Partial<Student>): Promise<void> => {
    if (isMockMode) return;
    try {
        if (!db) throw new Error("Database not initialized");
        await db.collection(COLLECTION_NAME).doc(id).update({
            ...student,
            lastModified: new Date().toISOString()
        });
    } catch (error) {
        console.error("Error updating student", error);
        throw error;
    }
}

export const deleteStudent = async (id: string): Promise<void> => {
    if (isMockMode) return;
    try {
        if (!db) throw new Error("Database not initialized");
        await db.collection(COLLECTION_NAME).doc(id).delete();
    } catch (error) {
        console.error("Error deleting student", error);
        throw error;
    }
}

export const bulkImportStudents = async (students: Student[]): Promise<void> => {
  if (isMockMode) return;
  try {
    if (!db) throw new Error("Database not initialized");
    const batch = db.batch();

    students.forEach(student => {
      // Pastikan NISN bersih dari spasi
      const cleanNisn = String(student.nisn || '').trim();
      if (cleanNisn) {
          const ref = db!.collection(COLLECTION_NAME).doc(cleanNisn);
          batch.set(ref, { 
              ...student, 
              nisn: cleanNisn,
              idUnik: student.idUnik || cleanNisn,
              lastModified: new Date().toISOString()
          }, { merge: true });
      }
    });

    await batch.commit();
  } catch (error) {
    console.error("Error bulk importing:", error);
    throw error;
  }
};

