import React, { useState, useEffect, useMemo } from 'react';
import { deleteStudent, updateStudent, addStudent } from '../services/studentService';
import { Student, UserRole } from '../types';
import { db, isMockMode } from '../services/firebase';
import { toast } from 'sonner';
import Layout from './Layout';
import { 
  UsersGroupIcon, 
  PencilIcon, TrashIcon, Search, PlusIcon,
  Loader2, XCircleIcon, SaveIcon, UserIcon,
  AcademicCapIcon, PhoneIcon,
  EnvelopeIcon, MapPinIcon, ChevronDownIcon,
  SparklesIcon, IdentificationIcon, CalendarIcon,
  CheckCircleIcon, HeartIcon
} from './Icons';

const StudentData: React.FC<{ onBack: () => void, userRole: UserRole }> = ({ onBack, userRole }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [classList, setClassList] = useState<string[]>([]);

  const initialFormState: Partial<Student> = {
    namaLengkap: '',
    nisn: '',
    idUnik: '',
    nik: '',
    email: '',
    userlogin: '',
    tempatLahir: '',
    tanggalLahir: '',
    tingkatRombel: '',
    status: 'Aktif',
    jenisKelamin: 'Laki-laki',
    noTelepon: '',
    alamat: '',
    namaAyahKandung: '',
    namaIbuKandung: '',
    namaWali: ''
  };

  const [formData, setFormData] = useState<Partial<Student>>(initialFormState);

  // Load class list for penempatan rombel
  useEffect(() => {
    if (isMockMode) {
      setClassList(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
      return;
    }
    if (db) {
      db.collection('classes').get().then(snap => {
        setClassList(snap.docs.map(d => d.data().name).sort());
      }).catch(e => console.warn("Firestore permissions: classList", e.message));
    }
  }, []);

  // Sinkronisasi Real-time Database Siswa
  useEffect(() => {
    setLoading(true);
    if (isMockMode) {
        setTimeout(() => {
            setStudents([
                { id: '123', namaLengkap: 'ADELIA SRI SUNDARI', nisn: '0086806440', idUnik: '25002', tingkatRombel: 'XII IPA 1', status: 'Aktif', jenisKelamin: 'Perempuan' } as Student,
                { id: '124', namaLengkap: 'DIENDE ADELLYA AQILLA', nisn: '0086806447', idUnik: '25039', tingkatRombel: '', status: 'Aktif', jenisKelamin: 'Perempuan' } as Student
            ]);
            setLoading(false);
        }, 800);
        return;
    }

    if (!db) return;

    // Listening ke koleksi 'students' secara real-time
    const unsubscribe = db.collection('students')
        .orderBy('namaLengkap')
        .onSnapshot(
            snapshot => {
                const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
                setStudents(data);
                setLoading(false);
            }, 
            err => {
                console.error("Access denied or connection error:", err.message);
                setLoading(false);
            }
        );

    return () => unsubscribe();
  }, []);

  const processedStudents = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    if (!q) return students;
    return students.filter(s => 
        (s.namaLengkap || '').toLowerCase().includes(q) || 
        (s.nisn || '').includes(q) ||
        (s.idUnik || '').includes(q)
    );
  }, [students, searchQuery]);

  const handleAddNew = () => { 
    setEditingId(null); 
    setFormData({ ...initialFormState }); 
    setIsModalOpen(true); 
  };

  const handleEdit = (student: Student) => { 
    setEditingId(student.id || null); 
    setFormData({ ...student }); 
    setIsModalOpen(true); 
  };

  const handleDelete = async (student: Student) => {
      if (!student.id) return;
      if (window.confirm(`Hapus data permanen ${student.namaLengkap}?`)) {
          try { await deleteStudent(student.id); toast.success("Data dihapus."); }
          catch (e) { toast.error("Gagal menghapus."); }
      }
  };

  const handleSave = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!formData.namaLengkap || !formData.nisn) {
          toast.error("Nama dan NISN wajib diisi.");
          return;
      }
      setSaving(true);
      try {
          if (editingId) await updateStudent(editingId, formData);
          else await addStudent(formData as Student);
          toast.success("Database berhasil diperbarui.");
          setIsModalOpen(false);
      } catch (e: any) { 
          toast.error("Gagal: " + e.message); 
      } finally { 
          setSaving(false); 
      }
  };

  const canManage = userRole === UserRole.ADMIN || userRole === UserRole.DEVELOPER;

  return (
    <Layout title="Master Data Siswa" subtitle="Database Induk Terpusat" icon={UsersGroupIcon} onBack={onBack}>
      <div className="p-4 lg:p-8 pb-40 space-y-6">

        {/* Search & Action Bar */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-4 items-center">
            <div className="relative flex-1 w-full group">
                <Search className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                <input 
                    type="text" 
                    placeholder="Cari Nama, NISN, atau ID Unik..." 
                    value={searchQuery} 
                    onChange={(e) => setSearchQuery(e.target.value)} 
                    className="w-full bg-slate-50 dark:bg-slate-900 border border-transparent rounded-2xl py-4 pl-12 pr-4 text-xs font-black outline-none text-slate-800 dark:text-white shadow-inner focus:bg-white transition-all" 
                />
            </div>
            {canManage && (
                <button 
                    onClick={handleAddNew} 
                    className="w-full md:w-auto px-8 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase flex items-center justify-center gap-2 shadow-xl shadow-indigo-500/20 active:scale-95 transition-all"
                >
                    <PlusIcon className="w-4 h-4" /> Tambah Siswa
                </button>
            )}
        </div>

        {/* Sync Status Info */}
        <div className="flex items-center justify-between px-2">
            <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    Real-time: {processedStudents.length} Peserta Didik
                </p>
            </div>
            <span className="text-[8px] font-black text-indigo-500 uppercase tracking-[0.2em] bg-indigo-50 dark:bg-indigo-900/30 px-3 py-1 rounded-lg">Cloud Database Online</span>
        </div>

        {/* Cards Grid */}
        {loading ? (
            <div className="text-center py-24 flex flex-col items-center gap-4">
                <Loader2 className="w-12 h-12 animate-spin text-indigo-500 opacity-20" />
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] animate-pulse">Sinkronisasi Database...</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in duration-700">
                {processedStudents.map((s) => (
                    <div key={s.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.2rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col justify-between group transition-all hover:shadow-xl hover:border-indigo-100">
                        <div className="flex items-start justify-between mb-6">
                            <div className="flex items-center gap-4 min-w-0">
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-xl border shadow-sm shrink-0 transition-transform group-hover:scale-105 ${s.jenisKelamin === 'Perempuan' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                                    {(s.namaLengkap || '?').charAt(0)}
                                </div>
                                <div className="min-w-0">
                                    <h4 className="font-black text-slate-800 dark:text-white text-xs uppercase truncate leading-tight">{s.namaLengkap}</h4>
                                    <p className="text-[9px] font-mono font-bold text-slate-400 mt-1 uppercase tracking-tighter">ID: {s.idUnik || s.nisn}</p>
                                    <div className="flex gap-1.5 mt-2">
                                        <span className={`text-[7px] font-black uppercase px-2 py-0.5 rounded-md ${s.status === 'Aktif' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>{s.status}</span>
                                        {s.jenisKelamin === 'Perempuan' && <span className="bg-rose-50 text-rose-500 p-0.5 rounded-md"><HeartIcon className="w-2.5 h-2.5 fill-current" /></span>}
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-3">
                            <div className={`p-3 rounded-2xl border flex items-center justify-between ${s.tingkatRombel ? 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800' : 'bg-rose-50 border-rose-100 dark:bg-rose-900/10 dark:border-rose-900/30'}`}>
                                <div className="flex items-center gap-2">
                                    <BookOpenIcon className={`w-3.5 h-3.5 ${s.tingkatRombel ? 'text-indigo-500' : 'text-rose-500'}`} />
                                    <span className={`text-[9px] font-black uppercase tracking-widest ${s.tingkatRombel ? 'text-slate-600 dark:text-slate-300' : 'text-rose-600'}`}>
                                        {s.tingkatRombel || 'BELUM DISET'}
                                    </span>
                                </div>
                                {canManage && <button onClick={() => handleEdit(s)} className="text-[8px] font-black text-indigo-600 hover:underline">Kelola</button>}
                            </div>

                            {canManage && (
                                <div className="flex gap-2 pt-1">
                                    <button onClick={() => handleEdit(s)} className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-indigo-600 transition-all text-[9px] font-black uppercase"><PencilIcon className="w-3 h-3"/> Edit</button>
                                    <button onClick={() => handleDelete(s)} className="px-3 rounded-xl bg-slate-50 dark:bg-slate-800 text-slate-400 hover:text-rose-600 transition-all"><TrashIcon className="w-3.5 h-3.5"/></button>
                                </div>
                            )}
                        </div>
                    </div>
                ))}
                {processedStudents.length === 0 && (
                    <div className="col-span-full py-32 text-center bg-white dark:bg-[#151E32] rounded-[4rem] border border-dashed border-slate-200 dark:border-slate-800 shadow-inner">
                         <Search className="w-16 h-16 text-slate-100 dark:text-slate-800 mx-auto mb-4 opacity-20" />
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Data Tidak Ditemukan</p>
                    </div>
                )}
            </div>
        )}
      </div>

      {/* FORM MODAL (RE-ENGINEERED) */}
      {isModalOpen && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="bg-white dark:bg-[#0B1121] w-full max-w-2xl rounded-[3rem] shadow-2xl animate-in zoom-in duration-300 flex flex-col max-h-[92vh] border border-white/10 relative overflow-hidden">

                  <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-white dark:bg-[#0B1121] z-10">
                      <div>
                          <h3 className="text-base font-black text-slate-800 dark:text-white uppercase tracking-tight">{editingId ? 'Koreksi Data' : 'Registrasi Baru'}</h3>
                          <p className="text-[9px] font-bold text-indigo-500 uppercase mt-1 tracking-widest flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-ping"></div> Database Sync Active</p>
                      </div>
                      <button onClick={() => setIsModalOpen(false)} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
                          <XCircleIcon className="w-7 h-7" />
                      </button>
                  </div>

                  <div className="p-6 lg:p-8 overflow-y-auto custom-scrollbar flex-1 space-y-8 pb-12">
                      <form id="studentForm" onSubmit={handleSave} className="space-y-10">
                          <div className="space-y-5">
                              <h5 className="text-[9px] font-black text-indigo-500 uppercase tracking-[0.3em] flex items-center gap-2 border-b border-indigo-50 dark:border-indigo-900/30 pb-2">
                                  <IdentificationIcon className="w-3.5 h-3.5" /> Identitas Akademik
                              </h5>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                  <div className="space-y-1.5 md:col-span-2">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Lengkap *</label>
                                      <input required type="text" value={formData.namaLengkap || ''} onChange={e => setFormData({...formData, namaLengkap: e.target.value.toUpperCase()})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all" placeholder="NAMA SESUAI IJAZAH" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">NISN * (Primary ID)</label>
                                      <input required disabled={!!editingId} type="text" value={formData.nisn || ''} onChange={e => setFormData({...formData, nisn: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold disabled:opacity-50" placeholder="10 digit nomor induk" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">ID Unik Lokal (Digital)</label>
                                      <input type="text" value={formData.idUnik || ''} onChange={e => setFormData({...formData, idUnik: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" placeholder="ID Kartu Pelajar" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Rombel Penempatan</label>
                                      <div className="relative">
                                          <select value={formData.tingkatRombel || ''} onChange={e => setFormData({...formData, tingkatRombel: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold appearance-none cursor-pointer">
                                              <option value="">-- TANPA ROMBEL --</option>
                                              {classList.map(c => <option key={c} value={c}>{c}</option>)}
                                          </select>
                                          <ChevronDownIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                                      </div>
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Jenis Kelamin</label>
                                      <div className="grid grid-cols-2 gap-2">
                                          <button type="button" onClick={() => setFormData({...formData, jenisKelamin: 'Laki-laki'})} className={`py-3.5 rounded-xl border text-[9px] font-black uppercase transition-all ${formData.jenisKelamin === 'Laki-laki' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 text-slate-400'}`}>Laki-laki</button>
                                          <button type="button" onClick={() => setFormData({...formData, jenisKelamin: 'Perempuan'})} className={`py-3.5 rounded-xl border text-[9px] font-black uppercase transition-all ${formData.jenisKelamin === 'Perempuan' ? 'bg-rose-600 border-rose-600 text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 text-slate-400'}`}>Perempuan</button>
                                      </div>
