const StudentData: React.FC<{ onBack: () => void, userRole: UserRole }> = ({ onBack, userRole }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [classList, setClassList] = useState<string[]>([]);

  const initialFormState: Partial<Student> = {
    namaLengkap: '',
    nisn: '',
    idUnik: '',
    nik: '',
    email: '',
    userlogin: '',
    tempatLahir: '',
    tanggalLahir: '',
    tingkatRombel: '',
    status: 'Aktif',
    jenisKelamin: 'Laki-laki',
    noTelepon: '',
    alamat: '',
    namaAyahKandung: '',
    namaIbuKandung: '',
    namaWali: ''
  };

  const [formData, setFormData] = useState<Partial<Student>>(initialFormState);

  // Load class list for penempatan rombel
  useEffect(() => {
    if (isMockMode) {
      setClassList(['X IPA 1', 'X IPA 2', 'XI IPS 1', 'XI IPS 2', 'XII AGAMA']);
      return;
    }
    if (db) {
      db.collection('classes').get().then(snap => {
        setClassList(snap.docs.map(d => d.data().name).sort());
