                        <div className="space-y-3">
                            <div className={`p-3 rounded-2xl border flex items-center justify-between ${s.tingkatRombel ? 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800' : 'bg-rose-50 border-rose-100 dark:bg-rose-900/10 dark:border-rose-900/30'}`}>
