        const name = (s.namaLengkap || '').toLowerCase();
        // PERBAIKAN: Cast idUnik dan nisn menjadi string sebelum .includes()
        const id = String(s.idUnik || '').toLowerCase();
        const nisn = String(s.nisn || '').toLowerCase();
        return name.includes(q) || id.includes(q) || nisn.includes(q);
    });
  }, [students, searchQuery]);

  const handleAddNew = () => { 
    setEditingId(null); 
    setFormData({ ...initialFormState }); 
    setIsModalOpen(true); 
  };

  const handleEdit = (student: Student) => { 
    setEditingId(student.id || null); 
    setFormData({ ...student }); 
    setIsModalOpen(true); 
  };

  const handleDelete = async (student: Student) => {
      if (!student.id) return;
      if (window.confirm(`Hapus data permanen ${student.namaLengkap}?`)) {
          try { await deleteStudent(student.id); toast.success("Data dihapus."); }
          catch (e) { toast.error("Gagal menghapus."); }
      }
  };

  const handleSave = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!formData.namaLengkap || !formData.idUnik) {
          toast.error("Nama dan ID UNIK wajib diisi.");
          return;
      }
      setSaving(true);
      try {
          if (editingId) {
              await updateStudent(editingId, formData);
          } else {
              await addStudent(formData as Student);
          }
          toast.success("Database berhasil diperbarui.");
          setIsModalOpen(false);
      } catch (e: any) { 
          toast.error("Gagal: " + e.message); 
      } finally { 
          setSaving(false); 
      }
  };

  const canManage = userRole === UserRole.ADMIN || userRole === UserRole.DEVELOPER;

  return (
    <Layout title="Master Data Siswa" subtitle="Database Induk Terpusat" icon={UsersGroupIcon} onBack={onBack}>
      <div className="p-4 lg:p-8 pb-40 space-y-6">

        {/* Search & Action Bar */}
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-4 items-center">
