                                          <button type="button" onClick={() => setFormData({...formData, jenisKelamin: 'Perempuan'})} className={`py-3.5 rounded-xl border text-[9px] font-black uppercase transition-all ${formData.jenisKelamin === 'Perempuan' ? 'bg-rose-600 border-rose-600 text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 text-slate-400'}`}>Perempuan</button>
                                      </div>
                                  </div>
                              </div>
                          </div>

                          <div className="space-y-5">
                              <h5 className="text-[9px] font-black text-emerald-500 uppercase tracking-[0.3em] flex items-center gap-2 border-b border-emerald-50 dark:border-indigo-900/30 pb-2">
                                  <PhoneIcon className="w-3.5 h-3.5" /> Kontak & Domisili
                              </h5>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                  <div className="space-y-1.5">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Siswa</label>
                                      <input type="email" value={formData.email || ''} onChange={e => setFormData({...formData, email: e.target.value.toLowerCase()})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" placeholder="siswa@madrasah.id" />
                                  </div>
                                  <div className="space-y-1.5">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">No. WhatsApp Aktif</label>
                                      <input type="text" value={formData.noTelepon || ''} onChange={e => setFormData({...formData, noTelepon: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl px-5 py-4 text-xs font-bold" placeholder="08..." />
                                  </div>
                                  <div className="space-y-1.5 md:col-span-2">
                                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Alamat Lengkap</label>
                                      <textarea rows={2} value={formData.alamat || ''} onChange={e => setFormData({...formData, alamat: e.target.value})} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl p-5 text-xs font-bold outline-none focus:ring-4 focus:ring-indigo-500/10 resize-none shadow-inner" placeholder="Jalan, Desa, Kecamatan..."></textarea>
                                  </div>
                              </div>
                          </div>
                      </form>
                  </div>

                  <div className="p-6 border-t border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-[#0B1121] flex gap-4 z-10">
                      <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 bg-white dark:bg-slate-800 text-slate-500 font-black rounded-2xl border border-slate-200 dark:border-slate-700 active:scale-95 transition-all text-[10px] uppercase tracking-widest">Batal</button>
                      <button type="submit" form="studentForm" disabled={saving} className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white font-black py-4 rounded-2xl shadow-2xl shadow-indigo-500/20 transition-all flex items-center justify-center gap-3 active:scale-[0.98] disabled:opacity-50">
                        {saving ? <Loader2 className="w-5 h-5 animate-spin" /> : <SaveIcon className="w-5 h-5" />}
                        <span className="uppercase tracking-[0.2em] text-[10px]">{editingId ? 'TERAPKAN PERUBAHAN' : 'SIMPAN KE DATABASE'}</span>
                      </button>
                  </div>
              </div>
          </div>
      )}
    </Layout>
  );
};

