            setStudents([
                { id: '25002', namaLengkap: 'ADELIA SRI SUNDARI', nisn: '0086806440', idUnik: '25002', tingkatRombel: 'XII IPA 1', status: 'Aktif', jenisKelamin: 'Perempuan' } as Student,
                { id: '25039', namaLengkap: 'DIENDE ADELLYA AQILLA', nisn: '0086806447', idUnik: '25039', tingkatRombel: '', status: 'Aktif', jenisKelamin: 'Perempuan' } as Student
            ]);
            setLoading(false);
        }, 800);
        return;
    }

    if (!db) return;

    const unsubscribe = db.collection('students')
        .orderBy('namaLengkap')
        .onSnapshot(
            snapshot => {
                const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
                setStudents(data);
