                              <div className="min-w-0 flex-1">
                                  <h4 className="font-black text-slate-800 dark:text-white text-[11px] uppercase truncate">{user.namaLengkap}</h4>
                                  <p className="text-[9px] font-bold text-slate-400 truncate">{user.email}</p>
                              </div>
                          </div>
