  const [currentView, setCurrentView] = useState<ViewState>(ViewState.LOGIN);
  const [isDarkTheme, setIsDarkTheme] = useState(false);
  const [userRole, setUserRole] = useState<UserRole>(UserRole.GURU);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [authLoading, setAuthLoading] = useState(true);
  const [viewKey, setViewKey] = useState(0); 

  useEffect(() => {
      const savedTheme = localStorage.getItem('theme');
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      const shouldBeDark = savedTheme === 'dark' || (!savedTheme && prefersDark);

      setIsDarkTheme(shouldBeDark);
      if (shouldBeDark) document.documentElement.classList.add('dark');
      else document.documentElement.classList.remove('dark');

      const handleOnline = () => { setIsOnline(true); toast.success("Koneksi online."); };
      const handleOffline = () => { setIsOnline(false); toast.warning("Mode Offline Aktif."); };

      window.addEventListener('online', handleOnline);
      window.addEventListener('offline', handleOffline);

      if (isMockMode) {
          setAuthLoading(false); 
      } else if (auth) {
          const unsubscribeAuth = auth.onAuthStateChanged(async (user) => {
              if (user && db) {
                  try {
                      const userRef = db.collection('users').doc(user.uid);
                      const userDoc = await userRef.get();

                      if (userDoc.exists) {
                          const data = userDoc.data();
                          const role = data?.role as UserRole || UserRole.GURU;
                          setUserRole(role);
                          setCurrentView(prev => (prev === ViewState.LOGIN || prev === ViewState.REGISTER) ? ViewState.DASHBOARD : prev);
                      }
                  } catch (e: any) { 
                      console.warn("Auth sync failure:", e.message);
                  }
              }
              setAuthLoading(false);
          });
          return () => unsubscribeAuth();
      } else {
          setAuthLoading(false);
      }

      return () => {
          window.removeEventListener('online', handleOnline);
          window.removeEventListener('offline', handleOffline);
      };
  }, []);

  const handleNavigate = (view: ViewState) => {
    setViewKey(prev => prev + 1);
    setCurrentView(view);
  };

  const toggleTheme = () => {
    setIsDarkTheme(prev => {
        const next = !prev;
        localStorage.setItem('theme', next ? 'dark' : 'light');
        if (next) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
        return next;
    });
  };

  const handleLoginSuccess = (role: UserRole) => {
    setUserRole(role);
    handleNavigate(ViewState.DASHBOARD);
  };

  const handleLogout = async () => {
    if (!isMockMode && auth) await auth.signOut();
    setUserRole(UserRole.GURU);
    handleNavigate(ViewState.LOGIN);
  };

  const backToDashboard = () => handleNavigate(ViewState.DASHBOARD);

  if (authLoading) {
      return (
          <div className="fixed inset-0 h-screen w-full flex flex-col items-center justify-center bg-[#020617] z-[100]">
              <div className="relative z-10 flex flex-col items-center animate-in fade-in duration-500">
                  <div className="w-16 h-16 mb-6 opacity-40"><AppLogo className="w-full h-full" /></div>
                  <Loader2 className="w-6 h-6 text-indigo-500 animate-spin opacity-30" />
              </div>
          </div>
      );
  }

  const isLoginPage = currentView === ViewState.LOGIN || currentView === ViewState.REGISTER;

  const staffAbove = [UserRole.ADMIN, UserRole.DEVELOPER, UserRole.GURU, UserRole.STAF, UserRole.WALI_KELAS, UserRole.KEPALA_MADRASAH];
  const adminDevOnly = [UserRole.ADMIN, UserRole.DEVELOPER];
  const devOnly = [UserRole.DEVELOPER];

  const renderView = () => {
    return (
      <Suspense fallback={<PageLoader />}>
        <div key={viewKey} className="h-full w-full relative">
          {(() => {
            switch (currentView) {
              case ViewState.LOGIN: return <Login onLogin={handleLoginSuccess} onRegisterClick={() => handleNavigate(ViewState.REGISTER)} />;
              case ViewState.REGISTER: return <Register onLogin={handleLoginSuccess} onLoginClick={() => handleNavigate(ViewState.LOGIN)} />;
              case ViewState.DASHBOARD: return <Dashboard onNavigate={handleNavigate} isDarkMode={isDarkTheme} onToggleTheme={toggleTheme} userRole={userRole} onLogout={handleLogout} />;
              case ViewState.PROFILE: return <Profile onBack={backToDashboard} onLogout={handleLogout} />;
              case ViewState.SCHEDULE: return <Schedule onBack={backToDashboard} />;
              case ViewState.ALL_FEATURES: return <AllFeatures onBack={backToDashboard} onNavigate={handleNavigate} userRole={userRole} />;
              case ViewState.NEWS: return <News onBack={backToDashboard} />;
              case ViewState.ABOUT: return <About onBack={backToDashboard} />;
              case ViewState.LOGIN_HISTORY: return <LoginHistory onBack={backToDashboard} />;
              case ViewState.ID_CARD: return <IDCard onBack={backToDashboard} />;
              case ViewState.HISTORY: return <History onBack={backToDashboard} userRole={userRole} />;
              case ViewState.PREMIUM: return <Premium onBack={backToDashboard} />;
              case ViewState.ADVISOR: return <Advisor onBack={backToDashboard} />;
              case ViewState.MADRASAH_INFO: return <MadrasahInfo onBack={backToDashboard} />;
              case ViewState.KEMENAG_HUB: return <KemenagHub onBack={backToDashboard} />;
              case ViewState.CLASSES: return <ProtectedRoute allowedRoles={staffAbove} userRole={userRole} onBack={backToDashboard}><ClassList onBack={backToDashboard} userRole={userRole} /></ProtectedRoute>;
              case ViewState.SCANNER: return <ProtectedRoute allowedRoles={staffAbove} userRole={userRole} onBack={backToDashboard}><QRScanner onBack={backToDashboard} /></ProtectedRoute>;
              case ViewState.ATTENDANCE_HISTORY: return <AttendanceHistory onBack={backToDashboard} onNavigate={handleNavigate} userRole={userRole} />;
              case ViewState.PRESENSI: return <ProtectedRoute allowedRoles={staffAbove} userRole={userRole} onBack={backToDashboard}><Presensi onBack={backToDashboard} onNavigate={handleNavigate} /></ProtectedRoute>;
              case ViewState.CONTENT_GENERATION: return <ProtectedRoute allowedRoles={staffAbove} userRole={userRole} onBack={backToDashboard}><ContentGeneration onBack={backToDashboard} /></ProtectedRoute>;
              case ViewState.REPORTS: return <ProtectedRoute allowedRoles={adminDevOnly} userRole={userRole} onBack={backToDashboard}><Reports onBack={backToDashboard} /></ProtectedRoute>;
              case ViewState.JOURNAL: return <ProtectedRoute allowedRoles={staffAbove} userRole={userRole} onBack={backToDashboard}><TeachingJournal onBack={backToDashboard} userRole={userRole} /></ProtectedRoute>;
              case ViewState.ASSIGNMENTS: return <Assignments onBack={backToDashboard} userRole={userRole} />;
              case ViewState.GRADES:
              case ViewState.REPORT_CARDS: return <Grades onBack={backToDashboard} userRole={userRole} />;
              case ViewState.STUDENTS: return <ProtectedRoute allowedRoles={staffAbove} userRole={userRole} onBack={backToDashboard}><StudentData onBack={backToDashboard} userRole={userRole} /></ProtectedRoute>;
              case ViewState.STUDENT_USERS: return <ProtectedRoute allowedRoles={adminDevOnly} userRole={userRole} onBack={backToDashboard}><StudentUsers onBack={backToDashboard} /></ProtectedRoute>;
              case ViewState.TEACHERS: return <ProtectedRoute allowedRoles={staffAbove} userRole={userRole} onBack={backToDashboard}><TeacherData onBack={backToDashboard} userRole={userRole} /></ProtectedRoute>;
              case ViewState.LETTERS: return <Letters onBack={backToDashboard} userRole={userRole} />;
              case ViewState.POINTS: return <PointsView onBack={backToDashboard} />;
              case ViewState.ACADEMIC_YEAR: return <ProtectedRoute allowedRoles={adminDevOnly} userRole={userRole} onBack={backToDashboard}><AcademicYear onBack={backToDashboard} /></ProtectedRoute>;
              case ViewState.PROMOTION: return <ProtectedRoute allowedRoles={adminDevOnly} userRole={userRole} onBack={backToDashboard}><ClassPromotion onBack={backToDashboard} /></ProtectedRoute>;
              case ViewState.PUSAKA: return <GenericView title="Pusaka Kemenag" onBack={backToDashboard} description="Integrasi resmi dengan Pusaka Super Apps RI." />;
              case ViewState.CREATE_ACCOUNT: 
                return (
                    <ProtectedRoute allowedRoles={adminDevOnly} userRole={userRole} onBack={backToDashboard}>
                        <CreateAccount onBack={backToDashboard} userRole={userRole} />
                    </ProtectedRoute>
                );
              case ViewState.USER_MANAGEMENT:
                return (
                    <ProtectedRoute allowedRoles={adminDevOnly} userRole={userRole} onBack={backToDashboard}>
                        <UserManagement onBack={backToDashboard} onNavigate={handleNavigate} />
                    </ProtectedRoute>
                );
              case ViewState.DEVELOPER: return <ProtectedRoute allowedRoles={devOnly} userRole={userRole} onBack={backToDashboard}><DeveloperConsole onBack={backToDashboard} /></ProtectedRoute>;
              case ViewState.SETTINGS: return <Settings onBack={backToDashboard} onNavigate={handleNavigate} onLogout={handleLogout} isDarkMode={isDarkTheme} onToggleTheme={toggleTheme} userRole={userRole} />;
              default: return <GenericView title="Fitur" onBack={backToDashboard} />;
            }
          })()}
        </div>
      </Suspense>
    );
  };

  return (
    <div className="h-full w-full flex flex-col font-sans overflow-hidden bg-white dark:bg-[#020617] relative">
        {!isOnline && (
            <div className="fixed top-0 left-0 right-0 z-[1000] bg-orange-600 text-white text-[9px] font-black uppercase tracking-[0.2em] text-center py-1">
                Mode Offline Aktif
            </div>
        )}

        <div className="h-full w-full relative flex overflow-hidden z-10">
            {!isLoginPage && (
                <div className="hidden lg:block w-72 lg:w-80 shrink-0 h-full border-r border-slate-100 dark:border-slate-800 bg-white/50 dark:bg-[#0B1121]/50 backdrop-blur-xl z-40">
                    <Sidebar currentView={currentView} onNavigate={handleNavigate} userRole={userRole} onLogout={handleLogout} />
                </div>
            )}

            <div className="flex-1 flex flex-col h-full w-full relative overflow-hidden">
                <div className="flex-1 overflow-hidden relative">
                    {renderView()}
                </div>

                {!isLoginPage && (
                    <div className="lg:hidden shrink-0 z-50">
                        <BottomNav currentView={currentView} onNavigate={handleNavigate} userRole={userRole} />
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { LockIcon, ArrowRightIcon, Loader2, ShieldCheckIcon, AppLogo, EnvelopeIcon, ArrowPathIcon } from './Icons';
import { UserRole } from '../types';
import { auth, db, isMockMode } from '../services/firebase';
import { toast } from 'sonner';

interface LoginProps {
  onLogin: (role: UserRole) => void;
  onRegisterClick?: () => void; // Tambahan
}

const Login: React.FC<LoginProps> = ({ onLogin, onRegisterClick }) => {
  // Set default ke admin@admin.id sesuai permintaan
  const [email, setEmail] = useState('admin@admin.id');
  const [password, setPassword] = useState('admin');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const u = email.trim();
    const p = password.trim();

    // --- LOGIKA LOGIN SIMULASI (Mock Mode) ---
    if (isMockMode) {
      setTimeout(() => {
        const lowerU = u.toLowerCase();
        let detectedRole = UserRole.GURU;

        // Prioritas deteksi admin@admin.id
        if (lowerU === 'admin@admin.id' || lowerU.includes('admin')) {
            detectedRole = UserRole.ADMIN;
        } else if (lowerU.includes('siswa')) {
            detectedRole = UserRole.SISWA;
        } else if (lowerU.includes('dev')) {
            detectedRole = UserRole.DEVELOPER;
        }

        onLogin(detectedRole);
        toast.success(`Mode Simulasi: Masuk sebagai ${detectedRole.toUpperCase()}`);
      }, 800);
      return;
    }

    // --- LOGIKA LOGIN REAL (FIREBASE) ---
    try {
        if (!auth || !db) throw new Error("Layanan database tidak tersedia.");

        // 1. Sign-in ke Firebase Auth
        let userCredential;
        try {
            userCredential = await auth.signInWithEmailAndPassword(u, p);
        } catch (signInErr: any) {
            // Jika akun admin@admin.id belum ada (invalid-credential atau user-not-found)
            // Coba daftarkan otomatis sebagai Admin Utama
            if (u === 'admin@admin.id' && (signInErr.code === 'auth/invalid-credential' || signInErr.code === 'auth/user-not-found')) {
                console.log("Admin account not found. Attempting auto-registration...");
                try {
                    userCredential = await auth.createUserWithEmailAndPassword(u, p);
                    toast.info("Akun Admin Utama berhasil diinisialisasi.");
                } catch (createErr: any) {
                    // Jika password terlalu lemah atau email sudah ada dengan password beda
                    throw signInErr; 
                }
            } else {
                throw signInErr;
            }
        }

        const user = userCredential.user;

        if (user) {
            // 2. Ambil peran (role) dari Firestore users collection
            const userDoc = await db.collection('users').doc(user.uid).get();

            if (userDoc.exists) {
                const role = userDoc.data()?.role as UserRole || UserRole.GURU;
                onLogin(role);
                toast.success(`Selamat datang, ${user.displayName || 'Administrator'}`);
            } else {
                // Auto-provisioning dokumen Firestore untuk admin default jika belum ada
                if (u === 'admin@admin.id') {
                    const adminData = {
                        uid: user.uid,
                        displayName: 'Sistem Administrator',
                        email: u,
                        role: UserRole.ADMIN,
                        status: 'Active',
                        createdAt: new Date().toISOString()
                    };
                    await db.collection('users').doc(user.uid).set(adminData);
                    onLogin(UserRole.ADMIN);
                    toast.success("Profil Administrator dikonfigurasi.");
                } else {
                    // Default role untuk user lain yang baru daftar lewat login
                    onLogin(UserRole.GURU);
                }
            }
        }
    } catch (err: any) {
        setLoading(false);
        console.error("Login Error:", err.code, err.message);

        if (err.code === 'auth/invalid-credential' || err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password') {
            setError('Email atau Password salah.');
        } else if (err.code === 'auth/too-many-requests') {
            setError('Terlalu banyak percobaan. Coba lagi nanti.');
        } else if (err.code === 'auth/network-request-failed') {
            setError('Koneksi internet bermasalah.');
        } else {
            setError('Gagal masuk: ' + (err.message || 'Kesalahan sistem'));
        }
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fafc] dark:bg-[#020617] transition-colors duration-500 relative overflow-hidden">

      {loading && (
          <div className="absolute inset-0 z-[100] flex flex-col items-center justify-center bg-white/90 dark:bg-[#020617]/95 backdrop-blur-xl animate-in fade-in duration-500">
              <div className="w-20 h-20 mb-8 animate-pulse">
                  <AppLogo className="w-full h-full drop-shadow-[0_0_20px_rgba(79,70,229,0.3)]" />
              </div>
              <div className="flex items-center gap-3">
                  <Loader2 className="w-5 h-5 text-indigo-500 animate-spin" />
                  <p className="text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-[0.4em]">Memverifikasi Otoritas...</p>
              </div>
          </div>
      )}

      <div className="hidden lg:flex flex-1 bg-gradient-to-br from-indigo-700 via-blue-600 to-indigo-900 relative items-center justify-center p-12 overflow-hidden">
          <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 mix-blend-overlay"></div>
          <div className="relative z-10 text-center max-w-lg">
              <div className="inline-flex mb-8">
                <AppLogo className="w-32 h-32" />
              </div>
              <h1 className="text-5xl font-black text-white mb-6 leading-tight tracking-tight text-shadow-xl">IMAM <br/>Digital Hub</h1>
              <p className="text-indigo-100 text-lg opacity-80 font-medium">Sistem Manajemen Terintegrasi MAN 1 Hulu Sungai Tengah.</p>
          </div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center p-6 md:p-12 relative h-full">
        <div className="w-full max-w-sm z-10 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="lg:hidden text-center mb-10">
                <AppLogo className="w-20 h-20 mx-auto" />
            </div>

            <div className="text-center lg:text-left">
                <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight uppercase">Login Akses</h2>
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mt-1">IMAM School Management v6.2</p>
            </div>

            <form onSubmit={handleLogin} className="space-y-5">
                <div className="space-y-4">
                    <div className="group">
                        <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Email Administrator</label>
                        <div className="relative">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors">
                                <EnvelopeIcon className="w-5 h-5" />
                            </div>
                            <input 
                                type="email" value={email} onChange={(e) => setEmail(e.target.value)}
                                className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-900 dark:text-white placeholder-slate-300 focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all font-bold text-sm shadow-sm"
                                placeholder="admin@admin.id" required
                            />
                        </div>
                    </div>

                    <div className="group">
                        <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Password</label>
                        <div className="relative">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors">
                                <LockIcon className="w-5 h-5" />
                            </div>
                            <input 
                                type="password" value={password} onChange={(e) => setPassword(e.target.value)}
                                className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 text-slate-900 dark:text-white placeholder-slate-300 focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all font-bold text-sm shadow-sm"
                                placeholder="••••••••" required
                            />
                        </div>
                    </div>
                </div>

                {error && (
                    <div className="p-4 rounded-2xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-[10px] font-black uppercase tracking-widest flex items-center gap-3 animate-bounce border border-red-100 dark:border-red-900/30">
                        <ShieldCheckIcon className="w-4 h-4" /> {error}
                    </div>
                )}

                <button 
                    type="submit" disabled={loading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-black py-4 rounded-2xl shadow-xl shadow-indigo-500/20 transition-all active:scale-[0.98] flex items-center justify-center gap-3 group relative overflow-hidden"
                >
                    <span className="uppercase tracking-[0.2em] text-xs relative z-10">Buka Sesi Admin</span>
                    <ArrowRightIcon className="w-5 h-5 relative z-10 group-hover:translate-x-1 transition-transform" />
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                </button>
            </form>

            <div className="text-center pt-4">
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-3">Belum memiliki akun?</p>
                <button 
                  onClick={onRegisterClick}
                  className="px-8 py-3 bg-slate-100 dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 rounded-xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-indigo-50 transition-all border border-transparent hover:border-indigo-100"
                >
                    Daftar Akun Baru
                </button>
            </div>

            <div className="text-center mt-12">
                <p className="text-[9px] font-black text-slate-300 dark:text-slate-700 uppercase tracking-[0.3em]">MAN 1 Hulu Sungai Tengah</p>
            </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

