            </div>
            <div className="text-center mt-12"><p className="text-[9px] font-black text-slate-300 dark:text-slate-700 uppercase tracking-[0.3em]">MAN 1 Hulu Sungai Tengah</p></div>
        </div>
      </div>
    </div>
  );
