          setStep(2);
          toast.success(`Halo, ${data?.namaLengkap.split(' ')[0]}!`);
      } catch (err) { setLoading(false); setError("Gagal memverifikasi data."); }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (password !== confirmPassword) { setError('Konfirmasi kata sandi tidak cocok'); return; }
    setLoading(true);
    try {
        if (isMockMode) {
            setTimeout(() => { onLogin(UserRole.SISWA); toast.success("Email Berhasil Didaftarkan!"); }, 1000);
            return;
        }
        const userCredential = await auth!.createUserWithEmailAndPassword(email, password);
        if (userCredential.user) {
            const uid = userCredential.user.uid;
            const displayName = regMode === 'student' ? verifiedStudent.namaLengkap : name;
            await userCredential.user.updateProfile({ displayName });
            const userData = { uid, displayName, email, role: UserRole.SISWA, createdAt: new Date().toISOString(), status: 'Active' };
            await db!.collection('users').doc(uid).set(userData);
            if (regMode === 'student') {
                await db!.collection('students').doc(verifiedStudent.id).update({ accountStatus: 'Active', linkedUserId: uid, email });
                await db!.collection('pengguna_siswa').doc(uid).set({ ...verifiedStudent, uid, email });
            }
        }
        onLogin(UserRole.SISWA);
    } catch (err: any) { setError('Gagal mendaftar: ' + err.message); } finally { setLoading(false); }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-[#f8fafc] dark:bg-[#020617] text-slate-900 dark:text-white relative overflow-hidden">
      <div className="flex-1 flex flex-col justify-center px-6 z-10 relative">
        <div className="w-full max-w-md mx-auto bg-white/90 dark:bg-[#0B1121]/95 backdrop-blur-xl border border-white/60 dark:border-slate-800 rounded-[3rem] p-8 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="mb-8 text-center">
                <div className="w-16 h-16 bg-indigo-600 rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-xl shadow-indigo-500/20"><AppLogo className="w-10 h-10" /></div>
                <h1 className="text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tight leading-none">Pendaftaran Akun</h1>
                <p className="text-[10px] font-bold text-slate-400 uppercase mt-3 tracking-widest">Portal Digital MAN 1 HST</p>
            </div>

            {regMode === 'student' && step === 1 ? (
                <form onSubmit={handleVerifyStudent} className="space-y-5 animate-in fade-in slide-in-from-right-4">
                    <div className="space-y-4">
                        <div className="group">
                            <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">NISN (10 Digit)</label>
                            <div className="relative">
                                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors"><QrCodeIcon className="w-5 h-5" /></div>
                                <input type="text" value={nisn} onChange={(e) => setNisn(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 font-bold text-sm outline-none" placeholder="0086..." required />
                            </div>
                        </div>
                        <div className="group">
                            <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Tanggal Lahir</label>
                            <div className="relative">
                                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors"><CalendarIcon className="w-5 h-5" /></div>
                                <input type="date" value={birthDate} onChange={(e) => setBirthDate(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 font-bold text-sm outline-none" required />
                            </div>
                        </div>
                    </div>
                    {error && <div className="p-4 rounded-2xl bg-red-50 text-red-600 text-[10px] font-black uppercase text-center">{error}</div>}
                    <button type="submit" disabled={loading} className="w-full bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-xl flex items-center justify-center gap-3">
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <><span className="uppercase tracking-widest text-xs">Verifikasi Data</span><ArrowRightIcon className="w-5 h-5" /></>}
                    </button>
                </form>
            ) : (
                <form onSubmit={handleRegister} className="space-y-5 animate-in fade-in slide-in-from-right-4">
                    {verifiedStudent && (
                        <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-2xl flex items-center gap-4 mb-4">
                            <div className="w-10 h-10 rounded-xl bg-emerald-500 text-white flex items-center justify-center shrink-0"><CheckCircleIcon className="w-6 h-6" /></div>
                            <div className="min-w-0"><p className="text-[11px] font-black text-slate-800 uppercase truncate">{verifiedStudent.namaLengkap}</p><p className="text-[9px] font-bold text-emerald-600 uppercase mt-0.5">{verifiedStudent.tingkatRombel}</p></div>
                        </div>
                    )}
                    <div className="space-y-4">
                        <div className="group">
                            <label className="block text-[9px] font-black text-slate-400 uppercase ml-1 mb-1.5">Email Aktif</label>
                            <div className="relative">
                                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"><EnvelopeIcon className="w-5 h-5" /></div>
                                <input type="email" value={email} onChange={(e) => setEmail(e.target.value.toLowerCase())} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl py-4 pl-12 pr-4 font-bold text-sm" placeholder="alamat@email.com" required />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 rounded-2xl py-4 px-5 font-bold text-sm" placeholder="Sandi" required />
                            <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 rounded-2xl py-4 px-5 font-bold text-sm" placeholder="Ulangi" required />
                        </div>
                    </div>
                    {error && <div className="p-4 rounded-2xl bg-red-50 text-red-600 text-[10px] font-black uppercase text-center">{error}</div>}
                    <button type="submit" disabled={loading} className="w-full bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-xl flex items-center justify-center gap-2">
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <span className="uppercase tracking-widest text-xs">Aktifkan Akun</span>}
                    </button>
                </form>
            )}

            <div className="mt-10 pt-6 border-t border-slate-100 text-center">
                <button onClick={onLoginClick} className="text-indigo-600 font-black text-xs uppercase tracking-widest hover:underline">Sudah punya akun? Masuk</button>
            </div>
        </div>
      </div>
    </div>
  );
};

