                setStats({ students: 842, teachers: 56, classes: 24, attendanceToday: 92 });
                setLoading(false);
            }, 800);
            return;
        }
        if (db) {
            const [s, t, c] = await Promise.all([
                db.collection('students').get(),
                db.collection('teachers').get(),
                db.collection('classes').get()
            ]);
            setStats({ students: s.size, teachers: t.size, classes: c.size, attendanceToday: 0 });
            setLoading(false);
        }
    };
    fetchStats();
  }, []);

  return (
    <div className="flex flex-col h-full bg-[#f8fafc] dark:bg-[#020617] overflow-hidden transition-colors duration-500">
