import React, { useState, useEffect, useMemo } from 'react';
import { deleteStudent, updateStudent, addStudent } from '../services/studentService';
import { Student, UserRole } from '../types';
import { db, auth, isMockMode } from '../services/firebase';
import { toast } from 'sonner';
import Layout from './Layout';
import { 
  UsersGroupIcon, PencilIcon, TrashIcon, Search, PlusIcon,
  Loader2, XCircleIcon, SaveIcon, IdentificationIcon,
  BookOpenIcon, EnvelopeIcon
} from './Ikon';

const DataSiswa: React.FC<{ onBack: () => void, userRole: UserRole }> = ({ onBack, userRole }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [classList, setClassList] = useState<string[]>([]);

  const [formData, setFormData] = useState<Partial<Student>>({
    namaLengkap: '', nisn: '', idUnik: '', tingkatRombel: '', status: 'Aktif', jenisKelamin: 'Laki-laki'
  });

  useEffect(() => {
    if (isMockMode) { setClassList(['X IPA 1', 'XI IPS 1', 'XII AGAMA']); return; }
    if (db) db.collection('classes').get().then(snap => setClassList(snap.docs.map(d => d.data().name).sort()));
  }, []);

  useEffect(() => {
    if (isMockMode) { setStudents([{ id: '1', namaLengkap: 'ADELIA SRI SUNDARI', nisn: '0086806440', idUnik: '25002', tingkatRombel: 'XII IPA 1', status: 'Aktif', jenisKelamin: 'Perempuan' } as Student]); setLoading(false); return; }
    if (!db) return;
    const unsub = db.collection('students').orderBy('namaLengkap').onSnapshot(snap => {
        setStudents(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student)));
        setLoading(false);
    });
    return () => unsub();
  }, []);

  const processedStudents = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    if (!q) return students;
    return students.filter(s => (s.namaLengkap || '').toLowerCase().includes(q) || String(s.idUnik).includes(q));
  }, [students, searchQuery]);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
        if (editingId) await updateStudent(editingId, formData);
        else await addStudent(formData as Student);
        toast.success("Database diperbarui.");
        setIsModalOpen(false);
    } catch (e) { toast.error("Gagal menyimpan."); } finally { setSaving(false); }
  };

  return (
    <Layout title="Database Siswa" subtitle="Master Data Induk" icon={UsersGroupIcon} onBack={onBack}>
      <div className="p-4 lg:p-8 pb-40 space-y-6">
        <div className="bg-white dark:bg-[#151E32] p-5 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                <input type="text" placeholder="Cari Siswa..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border-transparent rounded-2xl py-4 pl-12 pr-4 text-xs font-black outline-none text-slate-800 dark:text-white" />
            </div>
            <button onClick={() => setIsModalOpen(true)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase flex items-center justify-center gap-2 shadow-xl"><PlusIcon className="w-4 h-4" /> Tambah</button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {processedStudents.map(s => (
                <div key={s.id} className="bg-white dark:bg-[#151E32] p-5 rounded-[2.2rem] border border-slate-100 dark:border-slate-800 shadow-sm">
                    <div className="flex items-center gap-4 mb-5">
                        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-xl ${s.jenisKelamin === 'Perempuan' ? 'bg-rose-50 text-rose-600' : 'bg-blue-50 text-blue-600'}`}>{s.namaLengkap.charAt(0)}</div>
                        <div className="min-w-0 flex-1">
                            <h4 className="font-black text-slate-800 dark:text-white text-xs uppercase truncate">{s.namaLengkap}</h4>
                            <p className="text-[9px] font-mono font-bold text-indigo-600 mt-1 uppercase">ID: {s.idUnik}</p>
                        </div>
                    </div>
                </div>
            ))}
        </div>
      </div>
    </Layout>
  );
};

export default DataSiswa;

