import React, { useEffect, useState, useRef, useCallback } from 'react';
import { Html5Qrcode, Html5QrcodeSupportedFormats } from 'html5-qrcode';
import { recordAttendanceByScan, AttendanceSession } from '../services/attendanceService';
import Layout from './Layout';
import { CheckCircleIcon, XCircleIcon, CameraIcon, ClockIcon, ArrowPathIcon } from './Ikon';
import { toast } from 'sonner';

const PemindaiQR: React.FC<{ onBack: () => void }> = ({ onBack }) => {
  const [session, setSession] = useState<AttendanceSession>('Masuk');
  const [notifications, setNotifications] = useState<any[]>([]);
  const scannerRef = useRef<Html5Qrcode | null>(null);

  useEffect(() => {
    const html5QrCode = new Html5Qrcode("reader-core", { formatsToSupport: [ Html5QrcodeSupportedFormats.QR_CODE ] });
    scannerRef.current = html5QrCode;
    html5QrCode.start({ facingMode: "environment" }, { fps: 20, qrbox: 250 }, (text) => {
        recordAttendanceByScan(text, session).then(res => {
            if (res.success) toast.success(`Absen Berhasil: ${res.student?.namaLengkap}`);
            else toast.error(res.message);
        });
    }, () => {});
    return () => { html5QrCode.stop().catch(() => {}); };
  }, [session]);

  return (
    <Layout title="Pemindai Presensi" subtitle={`${session} • Realtime`} icon={CameraIcon} onBack={onBack}>
      <div className="flex flex-col h-full bg-black relative">
          <div id="reader-core" className="flex-1 w-full h-full opacity-80"></div>
          <div className="absolute top-4 inset-x-4 flex gap-2 overflow-x-auto scrollbar-hide bg-black/40 p-2 rounded-2xl backdrop-blur-md">
              {['Masuk', 'Duha', 'Zuhur', 'Ashar', 'Pulang'].map(s => (
                  <button key={s} onClick={() => setSession(s as any)} className={`px-6 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest ${session === s ? 'bg-indigo-600 text-white' : 'bg-white/10 text-white/50'}`}>{s}</button>
              ))}
          </div>
      </div>
    </Layout>
  );
};

