import React, { useState, useEffect, useMemo } from 'react';
import Layout from './Layout';
import { db, isMockMode } from '../services/firebase';
import { CalendarIcon, Loader2, Search } from './Ikon';
import { format } from 'date-fns';
import { ViewState, UserRole, AttendanceRecord, Student } from '../types';

const RiwayatPresensi: React.FC<{ onBack: () => void, onNavigate: (v: ViewState) => void, userRole: UserRole }> = ({ onBack, onNavigate, userRole }) => {
  const [selectedDate, setSelectedDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!db) return;
    setLoading(true);
    const unsubS = db.collection('students').onSnapshot(s => setAllStudents(s.docs.map(d => ({ id: d.id, ...d.data() } as Student))));
    const unsubA = db.collection('attendance').where('date', '==', selectedDate).onSnapshot(s => {
        setAttendance(s.docs.map(d => ({ id: d.id, ...d.data() } as AttendanceRecord)));
        setLoading(false);
    });
    return () => { unsubS(); unsubA(); };
  }, [selectedDate]);

  return (
    <Layout title="Riwayat Kehadiran" subtitle="Log Harian" icon={CalendarIcon} onBack={onBack}>
      <div className="p-4 lg:p-6 pb-32 space-y-6">
        <input type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} className="w-full p-4 bg-white dark:bg-slate-800 rounded-2xl font-black text-xs uppercase outline-none shadow-sm" />
        {loading ? <div className="py-20 text-center"><Loader2 className="w-8 h-8 animate-spin mx-auto" /></div> : (
            <div className="space-y-4">
                {allStudents.map(s => {
                    const record = attendance.find(a => a.studentId === s.id);
                    return (
                        <div key={s.id} className="bg-white dark:bg-slate-800 p-4 rounded-[2rem] border border-slate-100 flex items-center justify-between">
                            <div><p className="text-[11px] font-black uppercase text-slate-800 dark:text-white">{s.namaLengkap}</p><p className="text-[9px] font-bold text-slate-400 mt-1">{s.tingkatRombel}</p></div>
                            <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase ${record ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>{record ? 'Hadir' : 'Alpha'}</span>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </Layout>
  );
};

export default RiwayatPresensi;

