import React, { useState, useEffect, Suspense, lazy } from 'react';
import { ViewState, UserRole } from '../tipe/tipe';
import { auth, db, isMockMode } from '../layanan/firebase';
import { toast } from 'sonner';
import { Loader2 } from '../komponen/Ikon';

// Impor Langsung
import Masuk from './Masuk';
import Beranda from './Beranda';
import PenjagaAkses from '../penjaga-akses/PenjagaAkses';

// Lazy Load Komponen
const Daftar = lazy(() => import('./Daftar'));
const Profil = lazy(() => import('../komponen/Profil'));
const BilahSamping = lazy(() => import('../komponen/BilahSamping'));
const NavigasiBawah = lazy(() => import('../komponen/NavigasiBawah'));
const DataSiswa = lazy(() => import('../komponen/DataSiswa'));
const DataGuru = lazy(() => import('../komponen/DataGuru'));
const PemindaiQR = lazy(() => import('../komponen/PemindaiQR'));
const RiwayatPresensi = lazy(() => import('../komponen/RiwayatPresensi'));

const PemuatHalaman = () => (
    <div className="h-full w-full flex flex-col items-center justify-center bg-white/50 dark:bg-[#020617]/50 backdrop-blur-sm">
        <Loader2 className="w-10 h-10 text-indigo-500 animate-spin opacity-40 mb-4" />
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Memuat Modul...</p>
    </div>
);

const Aplikasi: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.LOGIN);
  const [userRole, setUserRole] = useState<UserRole>(UserRole.GURU);
  const [authLoading, setAuthLoading] = useState(true);

  useEffect(() => {
      if (isMockMode) {
          setAuthLoading(false);
      } else if (auth) {
          const unsubscribe = auth.onAuthStateChanged(async (user) => {
              if (user && db) {
                  const userDoc = await db.collection('users').doc(user.uid).get();
                  if (userDoc.exists) {
                      setUserRole(userDoc.data()?.role as UserRole || UserRole.GURU);
                      setCurrentView(ViewState.DASHBOARD);
                  }
              }
              setAuthLoading(false);
          });
          return () => unsubscribe();
      }
  }, []);

  const navigasi = (view: ViewState) => setCurrentView(view);

  if (authLoading) return <PemuatHalaman />;

  const isHalamanLogin = currentView === ViewState.LOGIN || currentView === ViewState.REGISTER;

  return (
    <div className="h-full w-full flex overflow-hidden bg-white dark:bg-[#020617]">
        {!isHalamanLogin && (
            <div className="hidden lg:block w-80 h-full border-r border-slate-100 dark:border-slate-800">
                <Suspense fallback={<Loader2/>}><BilahSamping currentView={currentView} onNavigate={navigasi} userRole={userRole} /></Suspense>
            </div>
        )}

        <div className="flex-1 flex flex-col h-full overflow-hidden relative">
            <main className="flex-1 overflow-hidden relative">
                <Suspense fallback={<PemuatHalaman />}>
                    {(() => {
                        switch (currentView) {
                            case ViewState.LOGIN: return <Masuk onLogin={(role) => { setUserRole(role); navigasi(ViewState.DASHBOARD); }} onRegisterClick={() => navigasi(ViewState.REGISTER)} />;
                            case ViewState.REGISTER: return <Daftar onLogin={(role) => { setUserRole(role); navigasi(ViewState.DASHBOARD); }} onLoginClick={() => navigasi(ViewState.LOGIN)} />;
                            case ViewState.DASHBOARD: return <Beranda onNavigate={navigasi} userRole={userRole} onLogout={() => auth.signOut().then(() => navigasi(ViewState.LOGIN))} />;
                            case ViewState.PROFILE: return <Profil onBack={() => navigasi(ViewState.DASHBOARD)} onLogout={() => auth.signOut().then(() => navigasi(ViewState.LOGIN))} />;
                            case ViewState.STUDENTS: return <PenjagaAkses allowedRoles={[UserRole.ADMIN, UserRole.GURU]} userRole={userRole} onBack={() => navigasi(ViewState.DASHBOARD)}><DataSiswa onBack={() => navigasi(ViewState.DASHBOARD)} userRole={userRole} /></PenjagaAkses>;
                            case ViewState.TEACHERS: return <PenjagaAkses allowedRoles={[UserRole.ADMIN]} userRole={userRole} onBack={() => navigasi(ViewState.DASHBOARD)}><DataGuru onBack={() => navigasi(ViewState.DASHBOARD)} userRole={userRole} /></PenjagaAkses>;
                            case ViewState.SCANNER: return <PemindaiQR onBack={() => navigasi(ViewState.DASHBOARD)} />;
                            case ViewState.ATTENDANCE_HISTORY: return <RiwayatPresensi onBack={() => navigasi(ViewState.DASHBOARD)} onNavigate={navigasi} userRole={userRole} />;
                            default: return <Beranda onNavigate={navigasi} userRole={userRole} onLogout={() => auth.signOut()} />;
                        }
                    })()}
                </Suspense>
            </main>

            {!isHalamanLogin && (
                <div className="lg:hidden shrink-0 z-50">
                    <Suspense fallback={<div className="h-16"/>}><NavigasiBawah currentView={currentView} onNavigate={navigasi} userRole={userRole} /></Suspense>
                </div>
            )}
        </div>
    </div>
  );
};

