import React, { useState } from 'react';
import { auth, db, isMockMode } from '../layanan/firebase';
import { UserRole } from '../tipe/tipe';
import { LockIcon, EnvelopeIcon, ArrowRightIcon, Loader2, AppLogo } from '../komponen/Ikon';
import { toast } from 'sonner';

interface MasukProps {
  onLogin: (role: UserRole) => void;
  onRegisterClick: () => void;
}

const Masuk: React.FC<MasukProps> = ({ onLogin, onRegisterClick }) => {
  const [email, setEmail] = useState('admin@admin.id');
  const [password, setPassword] = useState('admin');
  const [loading, setLoading] = useState(false);

  const handleMasuk = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    if (isMockMode) {
      onLogin(UserRole.ADMIN);
      return;
    }

    try {
        const cred = await auth.signInWithEmailAndPassword(email, password);
        const userDoc = await db.collection('users').doc(cred.user?.uid).get();
        if (userDoc.exists) {
            onLogin(userDoc.data()?.role as UserRole);
            toast.success("Berhasil masuk!");
        }
    } catch (err: any) {
        toast.error("Gagal masuk: " + err.message);
    } finally {
        setLoading(false);
    }
  };

  return (
    <div className="h-screen w-full flex items-center justify-center p-6 bg-slate-50 dark:bg-[#020617]">
      <div className="w-full max-w-sm space-y-8 animate-in fade-in slide-in-from-bottom-4">
        <div className="text-center">
            <AppLogo className="w-20 h-20 mx-auto mb-6" />
            <h2 className="text-2xl font-black uppercase text-slate-900 dark:text-white tracking-tight">Login IMAM</h2>
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-2">Sistem Manajemen Madrasah</p>
        </div>

        <form onSubmit={handleMasuk} className="space-y-4">
            <div className="relative">
                <EnvelopeIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
                <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full pl-12 pr-4 py-4 rounded-2xl bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 outline-none font-bold" placeholder="Email" />
            </div>
            <div className="relative">
                <LockIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} className="w-full pl-12 pr-4 py-4 rounded-2xl bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 outline-none font-bold" placeholder="Password" />
            </div>
            <button type="submit" disabled={loading} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2">
                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <>Masuk Sistem <ArrowRightIcon className="w-5 h-5" /></>}
            </button>
        </form>

        <div className="text-center pt-4">
            <button onClick={onRegisterClick} className="text-[10px] font-black uppercase text-indigo-600 tracking-widest">Daftar Akun Siswa</button>
        </div>
      </div>
    </div>
  );
};

