import React, { useState, useEffect, Suspense, lazy } from 'react';
import { ViewState, UserRole } from '../tipe/tipe';
import { auth, db, isMockMode } from '../layanan/firebase';
import { Loader2 } from '../komponen/Ikon';
import TataLetakPeran from '../tata-letak/TataLetakPeran';
import PenjagaAdmin from '../penjaga-akses/PenjagaAdmin';

// Impor Langsung
import Masuk from './Masuk';
import Beranda from './Beranda';

// Lazy Load Modul per Peran/Fitur
const DataSiswa = lazy(() => import('../komponen/DataSiswa'));
const DataGuru = lazy(() => import('../komponen/DataGuru'));
const PemindaiQR = lazy(() => import('../komponen/PemindaiQR'));
const RiwayatPresensi = lazy(() => import('../komponen/RiwayatPresensi'));
const Profil = lazy(() => import('../komponen/Profil'));

const PemuatHalaman = () => (
    <div className="h-full w-full flex flex-col items-center justify-center bg-white dark:bg-[#020617]">
        <Loader2 className="w-10 h-10 text-indigo-500 animate-spin opacity-40 mb-4" />
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sinkronisasi Modul...</p>
    </div>
);

const Aplikasi: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.LOGIN);
  const [userRole, setUserRole] = useState<UserRole>(UserRole.GURU);
  const [authLoading, setAuthLoading] = useState(true);

  useEffect(() => {
    if (isMockMode) {
      setAuthLoading(false);
    } else if (auth) {
      const unsubscribe = auth.onAuthStateChanged(async (user) => {
        if (user && db) {
          const userDoc = await db.collection('users').doc(user.uid).get();
          if (userDoc.exists) {
            setUserRole(userDoc.data()?.role as UserRole || UserRole.GURU);
            setCurrentView(ViewState.DASHBOARD);
          }
        }
        setAuthLoading(false);
      });
      return () => unsubscribe();
    }
  }, []);

  const navigasi = (view: ViewState) => setCurrentView(view);
  const handleLogout = () => auth.signOut().then(() => navigasi(ViewState.LOGIN));

  if (authLoading) return <PemuatHalaman />;

  // Alur Autentikasi
  if (currentView === ViewState.LOGIN) {
    return <Masuk onLogin={(role) => { setUserRole(role); navigasi(ViewState.DASHBOARD); }} onRegisterClick={() => navigasi(ViewState.REGISTER)} />;
  }

  return (
    <TataLetakPeran 
      peran={userRole} 
      tampilanSaatIni={currentView} 
      navigasi={navigasi} 
      onLogout={handleLogout}
    >
      <Suspense fallback={<PemuatHalaman />}>
        {(() => {
          switch (currentView) {
            case ViewState.DASHBOARD: 
              return <Beranda onNavigate={navigasi} userRole={userRole} onLogout={handleLogout} />;

            case ViewState.STUDENTS: 
              return (
                <PenjagaAdmin userRole={userRole} onBack={() => navigasi(ViewState.DASHBOARD)}>
                  <DataSiswa onBack={() => navigasi(ViewState.DASHBOARD)} userRole={userRole} />
                </PenjagaAdmin>
              );

            case ViewState.TEACHERS:
              return <DataGuru onBack={() => navigasi(ViewState.DASHBOARD)} userRole={userRole} />;

            case ViewState.SCANNER:
              return <PemindaiQR onBack={() => navigasi(ViewState.DASHBOARD)} />;

            case ViewState.PROFILE:
              return <Profil onBack={() => navigasi(ViewState.DASHBOARD)} onLogout={handleLogout} />;

            default:
              return <Beranda onNavigate={navigasi} userRole={userRole} onLogout={handleLogout} />;
          }
        })()}
      </Suspense>
    </TataLetakPeran>
  );
};

export default Aplikasi;

