import React, { useState, useEffect, Suspense, lazy } from 'react';
import { ViewState, UserRole } from '../tipe/user.type';
import { auth, db, isMockMode } from '../layanan/firebase';
import { Loader2 } from '../komponen/navigasi/Ikon';
import TataLetakPeran from '../tata-letak/TataLetakPeran';

// Halaman Inti
import HalamanMasuk from './(autentikasi)/masuk/halaman';
import HalamanDasbor from './dasbor/halaman';

// Lazy Components
const Profil = lazy(() => import('../komponen/Profil'));
const DataSiswa = lazy(() => import('../komponen/DataSiswa'));
const PemindaiQR = lazy(() => import('../komponen/PemindaiQR'));

const PemuatModul = () => (
    <div className="h-full w-full flex flex-col items-center justify-center bg-white dark:bg-[#020617]">
        <Loader2 className="w-10 h-10 text-indigo-500 animate-spin opacity-40 mb-4" />
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sinkronisasi Modul...</p>
    </div>
);

const Aplikasi: React.FC = () => {
  const [tampilan, setTampilan] = useState<ViewState>(ViewState.LOGIN);
  const [peran, setPeran] = useState<UserRole>(UserRole.GURU);
  const [memuat, setMemuat] = useState(true);

  useEffect(() => {
    if (isMockMode) {
      setMemuat(false);
    } else if (auth) {
      const unsubscribe = auth.onAuthStateChanged(async (user) => {
        if (user && db) {
          const userDoc = await db.collection('users').doc(user.uid).get();
          if (userDoc.exists) {
            setPeran(userDoc.data()?.role as UserRole || UserRole.GURU);
            setTampilan(ViewState.DASHBOARD);
          }
        }
        setMemuat(false);
      });
      return () => unsubscribe();
    }
  }, []);

  const navigasi = (view: ViewState) => setTampilan(view);
  const logout = () => auth.signOut().then(() => navigasi(ViewState.LOGIN));

  if (memuat) return <PemuatModul />;

  if (tampilan === ViewState.LOGIN) {
    return <HalamanMasuk onLogin={(r) => { setPeran(r); navigasi(ViewState.DASHBOARD); }} onRegisterClick={() => navigasi(ViewState.REGISTER)} />;
  }

  return (
    <TataLetakPeran 
      peran={peran} 
      tampilanSaatIni={tampilan} 
      navigasi={navigasi} 
      onLogout={logout}
    >
      <Suspense fallback={<PemuatModul />}>
        {(() => {
          switch (tampilan) {
            case ViewState.DASHBOARD: return <HalamanDasbor onNavigate={navigasi} userRole={peran} onLogout={logout} />;
            case ViewState.PROFILE: return <Profil onBack={() => navigasi(ViewState.DASHBOARD)} onLogout={logout} />;
            case ViewState.STUDENTS: return <DataSiswa onBack={() => navigasi(ViewState.DASHBOARD)} userRole={peran} />;
            case ViewState.SCANNER: return <PemindaiQR onBack={() => navigasi(ViewState.DASHBOARD)} />;
            default: return <HalamanDasbor onNavigate={navigasi} userRole={peran} onLogout={logout} />;
          }
        })()}
      </Suspense>
    </TataLetakPeran>
  );
};

export default Aplikasi;

