import { auth, db } from './firebase';
/** Fix: Updated import path to use unified tipe/tipe.ts */
import { UserRole, Pengguna } from '../tipe/tipe';

export const loginSistem = async (email: string, sandi: string) => {
  return await auth.signInWithEmailAndPassword(email, sandi);
};

export const keluarSistem = async () => {
  await auth.signOut();
};

export const dapatkanProfil = async (uid: string): Promise<Pengguna | null> => {
  const doc = await db.collection('users').doc(uid).get();
  if (doc.exists) {
    return { uid, ...doc.data() } as Pengguna;
  }
  return null;
};
